const ControlPanel: React.FC<ControlPanelProps> = ({
  onFileSelect,
  onAnalyze,
  onDetectCommunities,
  onSampleSelect,
  analysisResult,
  isAnalyzing,
  isDetectingCommunities,
  error,
  hasGraphData,
  graphData,
  selectedNode,
  selectedNodeStats,
  onNodeSelect,
  onClearSelection,
  isAdvancedMode,
  onToggleAdvancedMode,
  isGedcom
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
    e.target.value = '';
  };

  const getSelectedNodeNeighbors = () => {
    if (!selectedNode || !graphData) return [];

    const neighbors = new Set<string>();
    graphData.links.forEach(link => {
        const sourceId = typeof link.source === 'object' ? (link.source as NodeObject).id : link.source;
        const targetId = typeof link.target === 'object' ? (link.target as NodeObject).id : link.target;
        if(sourceId === selectedNode.id) neighbors.add(targetId);
        if(targetId === selectedNode.id) neighbors.add(sourceId);
    });

    const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));
    return Array.from(neighbors).map(id => nodeMap.get(id)).filter(Boolean) as NodeObject[];
  };

  const neighbors = getSelectedNodeNeighbors();
  const isLoading = isAnalyzing || isDetectingCommunities;

  return (
    <Card className="flex flex-col h-full p-5 overflow-y-auto">
      <div className="space-y-6">
          <div>
            <h2 className="text-xl font-bold text-white mb-3">Controls</h2>
            <div className="flex flex-col gap-3">
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    className="hidden"
                    accept=".gdcom,.ged,.txt"
                />
                <Button onClick={handleFileClick} icon={<UploadIcon />}>
                    Upload Graph File
                </Button>

                {/* Advanced Mode Toggle */}
                {isGedcom && (
                    <div className="flex items-center justify-between bg-gray-700 bg-opacity-30 p-2 rounded-md border border-gray-600">
                        <div className="flex flex-col">
                            <span className="text-sm font-semibold text-gray-200">Advanced Mode</span>
                            <span className="text-xs text-gray-500">Show places, dates & facts</span>
                        </div>
                        <button
                            onClick={onToggleAdvancedMode}
                            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:ring-offset-2 focus:ring-offset-gray-800 ${
                                isAdvancedMode ? 'bg-cyan-600' : 'bg-gray-600'
                            }`}
                            aria-pressed={isAdvancedMode}
                        >
                            <span
                                className={`${
                                    isAdvancedMode ? 'translate-x-6' : 'translate-x-1'
                                } inline-block h-4 w-4 transform rounded-full bg-white transition-transform`}
                            />
                        </button>
                    </div>
                )}

                <Button onClick={onAnalyze} disabled={!hasGraphData || isLoading} icon={isAnalyzing ? <Spinner /> : <BarChart2Icon />}>
                    {isAnalyzing ? 'Analyzing...' : 'Run Analysis'}
                </Button>
                <Button onClick={onDetectCommunities} disabled={!analysisResult || isLoading} icon={isDetectingCommunities ? <Spinner /> : <UsersIcon />}>
                    {isDetectingCommunities ? 'Detecting...' : 'Detect Communities'}
                </Button>
            </div>
        </div>
        <div>
            <h2 className="text-xl font-bold text-white mb-3">Sample Datasets</h2>
            <SampleDataSelector onSelect={onSampleSelect} />
        </div>
