import React, { useRef, useState, useMemo } from 'react';
import { AnalysisResult, NodeObject, CentralityResult, DegreeDistributionResult, GraphData, NodeAnalysisResult } from '../types';
import Button from './ui/Button';
import Card from './ui/Card';
import Spinner from './ui/Spinner';
import SampleDataSelector from './SampleDataSelector';
import Tooltip from './ui/Tooltip';
import { InfoIcon, AlertTriangleIcon, UploadIcon, BarChart2Icon, XCircleIcon, ChevronRightIcon, UsersIcon, SearchIcon } from './ui/Icons';

interface ControlPanelProps {
  onFileSelect: (file: File) => void;
  onAnalyze: () => void;
  onDetectCommunities: () => void;
  onSampleSelect: (content: string, type: 'ged' | 'txt', name: string) => void;
  analysisResult: AnalysisResult | null;
  isAnalyzing: boolean;
  isDetectingCommunities: boolean;
  error: string | null;
  hasGraphData: boolean;
  graphData: GraphData | null;
  selectedNode: NodeObject | null;
  selectedNodeStats: NodeAnalysisResult | null;
  onNodeSelect: (node: NodeObject) => void;
  onClearSelection: () => void;
  isAdvancedMode: boolean;
  onToggleAdvancedMode: () => void;
  isGedcom: boolean;
}

const StatItem: React.FC<{ label: string; value: React.ReactNode; tooltip?: string }> = ({ label, value, tooltip }) => (
    <div className="flex justify-between items-center py-2.5 border-b border-gray-700 last:border-b-0">
        <span className="text-sm text-gray-400 flex items-center gap-1.5">
            {label}
            {tooltip && (
                <Tooltip content={tooltip}>
                    <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                </Tooltip>
            )}
        </span>
        <span className="text-base font-semibold text-white">{String(value)}</span>
    </div>
);

const ListStatItem: React.FC<{ label: string; items: NodeObject[]; emptyText?: string; tooltip?: string }> = ({ label, items, emptyText = "None found", tooltip }) => (
    <div className="py-2.5 border-b border-gray-700 last:border-b-0">
        <div className="flex justify-between items-center">
            <span className="text-sm text-gray-400 flex items-center gap-1.5">
                {label}
                {tooltip && (
                    <Tooltip content={tooltip}>
                        <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                    </Tooltip>
                )}
            </span>
        </div>
        {items.length > 0 ? (
            <ul className="mt-1.5 pl-1 space-y-1">
                {items.map(item => (
                    <li key={item.id} className="text-sm text-gray-300 bg-gray-700 bg-opacity-50 px-2 py-1 rounded truncate" title={item.name || item.id}>
                       {item.name || item.id}
                    </li>
                ))}
            </ul>
        ) : (
            <p className="mt-1 text-sm text-right text-gray-500">{emptyText}</p>
        )}
    </div>
);

const RankedStatItem: React.FC<{ label: string; items: CentralityResult[]; emptyText?: string; tooltip?: string }> = ({ label, items, emptyText = "Not applicable", tooltip }) => (
     <div className="py-2.5 border-b border-gray-700 last:border-b-0">
        <div className="flex justify-between items-center mb-1">
            <span className="text-sm text-gray-400 flex items-center gap-1.5">
                {label}
                {tooltip && (
                     <Tooltip content={tooltip}>
                        <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                    </Tooltip>
                )}
            </span>
        </div>
        {items && items.length > 0 && items.some(i => i.value > 0) ? (
             <ol className="mt-1.5 pl-1 space-y-1">
                {items.map((item, index) => item.value > 0 && (
                    <li key={item.node.id} className="text-sm text-gray-300 bg-gray-700 bg-opacity-50 px-2 py-1 rounded flex justify-between items-center" title={item.node.name || item.node.id}>
                       <span className="truncate pr-2">{index + 1}. {item.node.name || item.node.id}</span>
                       <span className="font-semibold text-cyan-400 flex-shrink-0">{item.value.toFixed(2)}</span>
                    </li>
                ))}
            </ol>
        ) : (
             <p className="mt-1 text-sm text-right text-gray-500">{emptyText}</p>
        )}
    </div>
);

const DistributionStatItem: React.FC<{ label: string; items: DegreeDistributionResult[]; tooltip?: string }> = ({ label, items, tooltip }) => {
    if (!items || items.length === 0) {
        return (
             <div className="py-2.5 border-b border-gray-700 last:border-b-0">
                 <div className="flex justify-between items-center">
                     <span className="text-sm text-gray-400 flex items-center gap-1.5">
                        {label}
                        {tooltip && (
                            <Tooltip content={tooltip}>
                                <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                            </Tooltip>
                        )}
                     </span>
                     <p className="text-sm text-gray-500">Not applicable</p>
                 </div>
             </div>
        );
    }

    const maxCount = Math.max(...items.map(i => i.count), 0);

    return (
        <div className="py-2.5 border-b border-gray-700 last:border-b-0">
           <div className="flex justify-between items-center mb-2">
               <span className="text-sm text-gray-400 flex items-center gap-1.5">
                   {label}
                   {tooltip && (
                        <Tooltip content={tooltip}>
                           <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                       </Tooltip>
                   )}
               </span>
           </div>
           <div className="space-y-1.5 text-xs text-gray-400">
               <div className="flex items-center gap-2 text-gray-500">
                   <div className="w-12 font-mono text-right flex-shrink-0">Degree</div>
                   <div className="flex-grow text-center">Node Count</div>
               </div>
               {items.map(item => (
                   <div key={item.degree} className="flex items-center gap-2" title={`${item.count} nodes have ${item.degree} connections (degree)`}>
                       <div className="w-12 font-mono text-right flex-shrink-0">{item.degree}</div>
                       <div className="flex-grow bg-gray-700 bg-opacity-50 rounded-sm h-4">
                           <div
                               className="bg-cyan-600 h-4 rounded-sm transition-all duration-500 text-right pr-1 text-white/80 font-semibold"
                               style={{ width: maxCount > 0 ? `${(item.count / maxCount) * 100}%` : '0%' }}
                           >
                            {item.count}
                           </div>
                       </div>
                   </div>
               ))}
           </div>
       </div>
    );
};

const CommunityListStatItem: React.FC<{ 
  label: string; 
  communities: NodeObject[][]; 
  onNodeSelect: (node: NodeObject) => void; 
  tooltip?: string 
}> = ({ label, communities, onNodeSelect, tooltip }) => {
    const topCommunities = communities.slice(0, 5); // Show top 5 largest

    return (
        <div className="py-2.5 border-b border-gray-700 last:border-b-0">
            <div className="flex justify-between items-center mb-1">
                <span className="text-sm text-gray-400 flex items-center gap-1.5">
                    {label}
                    {tooltip && (
                         <Tooltip content={tooltip}>
                            <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                        </Tooltip>
                    )}
                </span>
                <span className="text-base font-semibold text-white">{communities.length} found</span>
            </div>
            {topCommunities.length > 0 ? (
                <div className="mt-1.5 pl-1 space-y-2">
                    {topCommunities.map((community, index) => (
                        <details key={index} className="bg-gray-700 bg-opacity-50 px-2 py-1.5 rounded group">
                            <summary className="text-sm text-gray-300 cursor-pointer list-none flex justify-between items-center font-semibold">
                                <span className="truncate">Community {index + 1} ({community.length} members)</span>
                                <ChevronRightIcon className="w-4 h-4 text-gray-400 transition-transform duration-200 group-open:rotate-90 flex-shrink-0" />
                            </summary>
                            <ul className="mt-2 pt-2 border-t border-gray-600 max-h-40 overflow-y-auto space-y-1">
                                {community.map(node => (
                                    <li key={node.id}>
                                        <button onClick={() => onNodeSelect(node)} className="w-full text-left text-xs text-gray-300 hover:text-cyan-400 truncate bg-gray-600 bg-opacity-50 px-2 py-1 rounded">
                                            {node.name || node.id}
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        </details>
                    ))}
                    {communities.length > 5 && <p className="text-xs text-gray-500 text-center pt-1">...and {communities.length - 5} more communities.</p>}
                </div>
            ) : (
                <p className="mt-1 text-sm text-right text-gray-500">None found</p>
            )}
        </div>
    );
};


const ControlPanel: React.FC<ControlPanelProps> = ({
  onFileSelect,
  onAnalyze,
  onDetectCommunities,
  onSampleSelect,
  analysisResult,
  isAnalyzing,
  isDetectingCommunities,
  error,
  hasGraphData,
  graphData,
  selectedNode,
  selectedNodeStats,
  onNodeSelect,
  onClearSelection,
  isAdvancedMode,
  onToggleAdvancedMode,
  isGedcom
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const handleFileClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      onFileSelect(e.target.files[0]);
    }
    e.target.value = '';
  };

  const filteredNodes = useMemo(() => {
    if (!searchQuery.trim() || !graphData) return [];
    const query = searchQuery.toLowerCase();
    return graphData.nodes.filter(node => 
        (node.name && node.name.toLowerCase().includes(query)) || 
        node.id.toLowerCase().includes(query)
    ).slice(0, 10); // Limit results to 10 for performance in dropdown
  }, [searchQuery, graphData]);

  const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
    setSearchQuery(e.target.value);
  };

  const getSelectedNodeNeighbors = () => {
    if (!selectedNode || !graphData) return [];

    const neighbors = new Set<string>();
    graphData.links.forEach(link => {
        const sourceId = typeof link.source === 'object' ? (link.source as NodeObject).id : link.source;
        const targetId = typeof link.target === 'object' ? (link.target as NodeObject).id : link.target;
        if(sourceId === selectedNode.id) neighbors.add(targetId);
        if(targetId === selectedNode.id) neighbors.add(sourceId);
    });

    const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));
    return Array.from(neighbors).map(id => nodeMap.get(id)).filter(Boolean) as NodeObject[];
  };

  const neighbors = getSelectedNodeNeighbors();
  const isLoading = isAnalyzing || isDetectingCommunities;

  return (
    <Card className="flex flex-col h-full p-5 overflow-y-auto">
      <div className="space-y-6">
          {hasGraphData && (
              <div>
                <h2 className="text-xl font-bold text-white mb-3">Search</h2>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <SearchIcon className="h-4 w-4 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        className="block w-full pl-10 pr-8 py-2 border border-gray-600 rounded-md leading-5 bg-gray-700 text-gray-300 placeholder-gray-500 focus:outline-none focus:bg-gray-600 focus:border-cyan-500 sm:text-sm transition duration-150 ease-in-out"
                        placeholder="Search by name or ID..."
                        value={searchQuery}
                        onChange={handleSearch}
                    />
                    {searchQuery && (
                        <button 
                            className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-white"
                            onClick={() => setSearchQuery('')}
                        >
                            <XCircleIcon className="h-4 w-4" />
                        </button>
                    )}
                </div>
                {searchQuery && (
                    <div className="mt-2 bg-gray-800 border border-gray-700 rounded-md shadow-lg max-h-60 overflow-y-auto relative z-20">
                        {filteredNodes.length > 0 ? (
                            <ul className="py-1">
                                {filteredNodes.map(node => (
                                    <li key={node.id}>
                                        <button
                                            className="w-full text-left px-4 py-2 text-sm text-gray-300 hover:bg-gray-700 hover:text-white flex items-center justify-between transition-colors"
                                            onClick={() => {
                                                onNodeSelect(node);
                                                setSearchQuery(''); 
                                            }}
                                        >
                                            <span className="truncate">{node.name || node.id}</span>
                                            {node.type && <span className={`text-[10px] uppercase ml-2 px-1.5 py-0.5 rounded ${
                                                node.type === 'person' ? 'bg-blue-900/50 text-blue-200' :
                                                node.type === 'place' ? 'bg-green-900/50 text-green-200' :
                                                node.type === 'date' ? 'bg-orange-900/50 text-orange-200' :
                                                'bg-gray-600 text-gray-300'
                                            }`}>{node.type}</span>}
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <div className="px-4 py-3 text-sm text-gray-500">No matching nodes found.</div>
                        )}
                    </div>
                )}
              </div>
          )}

          <div>
            <h2 className="text-xl font-bold text-white mb-3">Controls</h2>
            <div className="flex flex-col gap-3">
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={handleFileChange}
                    className="hidden"
                    accept=".gdcom,.ged,.txt"
                />
                <Button onClick={handleFileClick} icon={<UploadIcon />}>
                    Upload Graph File
                </Button>

                {/* Advanced Mode Toggle */}
                {isGedcom && (
                    <div className="flex items-center justify-between bg-gray-700 bg-opacity-30 p-2 rounded-md border border-gray-600">
                        <div className="flex flex-col">
                            <span className="text-sm font-semibold text-gray-200">Advanced Mode</span>
                            <span className="text-xs text-gray-500">Show places, dates & facts</span>
                        </div>
                        <button
                            onClick={onToggleAdvancedMode}
                            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none focus:ring-2 focus:ring-cyan-500 focus:ring-offset-2 focus:ring-offset-gray-800 ${
                                isAdvancedMode ? 'bg-cyan-600' : 'bg-gray-600'
                            }`}
                            aria-pressed={isAdvancedMode}
                        >
                            <span
                                className={`${
                                    isAdvancedMode ? 'translate-x-6' : 'translate-x-1'
                                } inline-block h-4 w-4 transform rounded-full bg-white transition-transform`}
                            />
                        </button>
                    </div>
                )}

                <Button onClick={onAnalyze} disabled={!hasGraphData || isLoading} icon={isAnalyzing ? <Spinner /> : <BarChart2Icon />}>
                    {isAnalyzing ? 'Analyzing...' : 'Run Analysis'}
                </Button>
                <Button onClick={onDetectCommunities} disabled={!analysisResult || isLoading} icon={isDetectingCommunities ? <Spinner /> : <UsersIcon />}>
                    {isDetectingCommunities ? 'Detecting...' : 'Detect Communities'}
                </Button>
            </div>
        </div>
        <div>
            <h2 className="text-xl font-bold text-white mb-3">Sample Datasets</h2>
            <SampleDataSelector onSelect={onSampleSelect} />
        </div>
      </div>

      {selectedNode && (
        <div className="mt-6 pt-6 border-t border-gray-700">
            <div className="flex justify-between items-center mb-2">
                <h2 className="text-xl font-bold text-white">Selected Node</h2>
                <button onClick={onClearSelection} className="text-gray-500 hover:text-white transition-colors">
                    <XCircleIcon className="w-6 h-6" />
                </button>
            </div>
            <div className="bg-gray-700 bg-opacity-50 p-3 rounded-md">
                <h3 className="font-bold text-cyan-400 truncate text-lg mb-0.5" title={selectedNode.name || selectedNode.id}>
                    {selectedNode.name || selectedNode.id}
                </h3>
                {selectedNode.type && (
                     <span className={`inline-block px-2 py-0.5 rounded text-[10px] uppercase font-bold tracking-wider mb-2 ${
                        selectedNode.type === 'person' ? 'bg-blue-900 text-blue-200' :
                        selectedNode.type === 'place' ? 'bg-green-900 text-green-200' :
                        selectedNode.type === 'date' ? 'bg-orange-900 text-orange-200' :
                        'bg-purple-900 text-purple-200'
                     }`}>
                        {selectedNode.type}
                     </span>
                )}

                <div className="space-y-1">
                   <StatItem 
                      label="Degree (Neighbors)" 
                      value={neighbors.length} 
                      tooltip="The total number of direct connections this node has." 
                   />

                   {selectedNodeStats ? (
                      <>
                        <h4 className="text-xs font-semibold text-cyan-400 uppercase tracking-wider pt-2 pb-1">Component Analysis</h4>
                        <StatItem 
                            label="Reachable Nodes" 
                            value={selectedNodeStats.reachableNodes} 
                            tooltip="The total number of nodes that can be reached from this node (size of its component)."
                        />
                        <StatItem 
                            label="Eccentricity" 
                            value={selectedNodeStats.eccentricity} 
                            tooltip="The maximum distance from this node to the farthest node in its component."
                        />
                        <StatItem 
                            label="Avg. Distance" 
                            value={selectedNodeStats.averageDistance.toFixed(2)} 
                            tooltip="The average number of steps required to reach any other node in the same component."
                        />
                        <StatItem 
                            label="Clustering Coeff" 
                            value={selectedNodeStats.clusteringCoefficient.toFixed(2)} 
                            tooltip="A measure of how connected this node's neighbors are to each other (0 to 1). A high value indicates a tight-knit cluster."
                        />
                      </>
                   ) : (
                      <div className="flex items-center gap-2 py-2 text-xs text-gray-400">
                          <Spinner /> Computing metrics...
                      </div>
                   )}
                </div>

                {neighbors.length > 0 && (
                    <div className="mt-3 pt-3 border-t border-gray-600">
                        <h4 className="text-xs font-semibold uppercase text-gray-500 mb-1">Neighbors ({neighbors.length})</h4>
                        <ul className="max-h-32 overflow-y-auto space-y-1 pr-1">
                            {neighbors.map(n => (
                                <li key={n.id}>
                                    <button onClick={() => onNodeSelect(n)} className="w-full text-left text-sm text-gray-300 hover:text-cyan-400 truncate bg-gray-600 bg-opacity-50 px-2 py-1 rounded">
                                        {n.name || n.id}
                                    </button>
                                </li>
                            ))}
                        </ul>
                    </div>
                )}
            </div>
        </div>
      )}

      {/* Analysis Results - unchanged code omitted for brevity but conceptually here */}
       <div className="flex-shrink-0 mt-6 pt-6 border-t border-gray-700 space-y-4">
        <div>
            <h2 className="text-xl font-bold text-white mb-2">Analysis Results</h2>
            {error && (
                <div className="bg-red-900 bg-opacity-50 border border-red-700 text-red-300 p-3 rounded-md flex items-start gap-3 my-4">
                    <AlertTriangleIcon className="w-5 h-5 mt-0.5 flex-shrink-0" />
                    <div>
                      <h3 className="font-semibold">Error</h3>
                      <p className="text-sm">{error}</p>
                    </div>
                </div>
            )}

            {analysisResult ? (
              <div className="space-y-1">
                  <h3 className="text-xs font-semibold text-cyan-400 uppercase tracking-wider pt-2 pb-1">Basic Stats</h3>
                  <StatItem label="Nodes" value={analysisResult.nodeCount} tooltip="Total unique nodes." />
                  <StatItem label="Edges" value={analysisResult.edgeCount} tooltip="Total connections." />
                  <StatItem 
                      label="Graph Density" 
                      value={analysisResult.graphDensity} 
