                      <h3 className="text-xs font-semibold text-cyan-400 uppercase tracking-wider pt-3 pb-1">Structure</h3>
                      <StatItem 
                        label="Avg. Gen Width" 
                        value={analysisResult.averageGenerationWidth}
                      />
                      <StatItem 
                        label="Avg. Leaf Depth" 
                        value={analysisResult.averageLeafDepth}
                      />
                    </>
                  )}

                  <h3 className="text-xs font-semibold text-cyan-400 uppercase tracking-wider pt-3 pb-1">Centrality</h3>
                  {analysisResult.centralityByConnections && <RankedStatItem
                      label="Top by Connections"
                      items={analysisResult.centralityByConnections}
                  />}
                  {analysisResult.betweennessCentrality && <RankedStatItem
                      label="Top by Betweenness"
                      items={analysisResult.betweennessCentrality}
                  />}

                  {analysisResult.communities && analysisResult.communities.length > 0 && (
                    <>
                      <h3 className="text-xs font-semibold text-cyan-400 uppercase tracking-wider pt-3 pb-1">Communities</h3>
                      <CommunityListStatItem
                          label="Detected Groups"
                          communities={analysisResult.communities}
                          onNodeSelect={onNodeSelect}
                      />
                    </>
                  )}
              </div>
            ) : (
              <div className="text-center py-8 text-gray-500">
                <p>Run analysis to see results.</p>
              </div>
            )}
        </div>
      </div>
    </Card>
  );
};

