import React, { useMemo, useRef, useState, useLayoutEffect } from 'react';
import ForceGraph2D from 'react-force-graph-2d';
import { GraphData, NodeObject, LinkObject, AnalysisResult } from '../types';

interface GraphVisualizerProps {
  fgRef: React.MutableRefObject<any>;
  graphData: GraphData;
  onNodeClick: (node: NodeObject, event: any) => void;
  onBackgroundClick: () => void;
  hoveredNode: NodeObject | null;
  onNodeHover: (node: NodeObject | null) => void;
  selectedNode: NodeObject | null;
  analysisResult: AnalysisResult | null;
  shortestPath: string[] | null;
}

const GraphVisualizer: React.FC<GraphVisualizerProps> = ({ 
  fgRef,
  graphData, 
  onNodeClick, 
  onBackgroundClick,
  hoveredNode,
  onNodeHover,
  selectedNode,
  analysisResult,
  shortestPath
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [size, setSize] = useState({ width: 0, height: 0 });

  useLayoutEffect(() => {
    if (!containerRef.current) return;
    const resizeObserver = new ResizeObserver(entries => {
      const entry = entries[0];
      if (entry) {
        const { width, height } = entry.contentRect;
        setSize({ width, height });
      }
    });
    resizeObserver.observe(containerRef.current);
    return () => resizeObserver.disconnect();
  }, []);

  const pathNodesSet = useMemo(() => new Set(shortestPath || []), [shortestPath]);
  const pathLinksSet = useMemo(() => {
      const links = new Set();
      if (!shortestPath || shortestPath.length < 2) return links;
      for (let i = 0; i < shortestPath.length - 1; i++) {
          const u = shortestPath[i];
          const v = shortestPath[i+1];
          graphData.links.forEach(link => {
              const s = typeof link.source === 'object' ? link.source.id : link.source;
              const t = typeof link.target === 'object' ? link.target.id : link.target;
              if ((s === u && t === v) || (s === v && t === u)) {
                  links.add(link);
              }
          });
      }
      return links;
  }, [shortestPath, graphData]);

  const {highlightNodes, highlightLinks} = useMemo(() => {
    const highlightNodes = new Set();
    const highlightLinks = new Set();
    const nodeToInspect = hoveredNode || selectedNode;

    if (nodeToInspect) {
      highlightNodes.add(nodeToInspect.id);
      graphData.links.forEach(link => {
        const sourceId = typeof link.source === 'object' ? (link.source as NodeObject).id : link.source;
        const targetId = typeof link.target === 'object' ? (link.target as NodeObject).id : link.target;
        if (sourceId === nodeToInspect.id || targetId === nodeToInspect.id) {
          highlightLinks.add(link);
          highlightNodes.add(sourceId);
          highlightNodes.add(targetId);
        }
      });
    }
    return { highlightNodes, highlightLinks };
  }, [graphData, hoveredNode, selectedNode]);

  const getLinkColor = (link: LinkObject) => {
    if (pathLinksSet.has(link)) return '#fbbf24'; // Golden path
    const isHighlighted = highlightLinks.has(link);
    let baseColor = '107, 114, 128'; 
    if (link.type === 'marriage') baseColor = '255, 165, 0';
    else if (link.type === 'parent-child') baseColor = '135, 206, 250';
    else if (link.type === 'event_link') baseColor = '74, 222, 128';

    if (hoveredNode || selectedNode || shortestPath) {
        if(isHighlighted || pathLinksSet.has(link)) return `rgba(${baseColor}, 0.9)`;
        return `rgba(107, 114, 128, 0.05)`;
    }
    return `rgba(${baseColor}, ${link.type === 'marriage' ? '0.9' : '0.5'})`;
  };

  const getNodeColor = (node: NodeObject) => {
    if (pathNodesSet.has(node.id)) return '#f59e0b'; // Path node color
    const nodeToInspect = hoveredNode || selectedNode;
    const isHighlighted = highlightNodes.has(node.id);

    if (nodeToInspect) {
        if (node.id === nodeToInspect.id) return '#facc15';
        if (isHighlighted) return '#22d3ee';
        return 'rgba(209, 213, 219, 0.2)';
    }

    switch (node.type) {
        case 'place': return '#16a34a'; 
        case 'date': return '#ea580c';
        case 'source': return '#9333ea';
        case 'person': return '#0284c7';
        default: return '#06b6d4';
    }
  }

  return (
    <div ref={containerRef} className="w-full h-full cursor-pointer">
      <ForceGraph2D
        ref={fgRef}
        width={size.width}
        height={size.height}
        graphData={graphData}
        nodeLabel={(node: NodeObject) => node.name || node.id}
        nodeVal={(node: NodeObject) => (selectedNode?.id === node.id || pathNodesSet.has(node.id)) ? 10 : 6}
        nodeColor={getNodeColor}
        linkColor={getLinkColor}
        linkWidth={(link: LinkObject) => (pathLinksSet.has(link) || highlightLinks.has(link)) ? 3 : 1}
        linkDirectionalParticles={(link: LinkObject) => (pathLinksSet.has(link) || highlightLinks.has(link)) ? 2 : 0}
        linkDirectionalParticleSpeed={0.01}
        backgroundColor="transparent"
        onNodeClick={onNodeClick}
        onNodeHover={onNodeHover}
        onBackgroundClick={onBackgroundClick}
        nodeCanvasObjectMode={() => 'after'}
        nodeCanvasObject={(node: any, ctx: CanvasRenderingContext2D) => {
            if (selectedNode?.id === node.id || pathNodesSet.has(node.id)) {
                const label = node.name || node.id;
                const fontSize = 4;
                ctx.font = `${fontSize}px Sans-Serif`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillStyle = '#fff';
                ctx.fillText(label, node.x, node.y + 10);

                // Glow effect
                ctx.beginPath();
                ctx.arc(node.x, node.y, 8, 0, 2 * Math.PI, false);
                ctx.fillStyle = 'rgba(250, 204, 21, 0.15)';
                ctx.fill();
            }
        }}
      />
    </div>
  );
};

export default GraphVisualizer;

import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangleIcon } from './ui/Icons';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
}

// Fix: Explicitly use React.Component with Props and State to ensure TypeScript recognizes state and props properties
class ErrorBoundary extends React.Component<Props, State> {
  // Fix: Explicitly define the state property for the class to resolve Property 'state' does not exist error
  public state: State = {
    hasError: false
  };

  constructor(props: Props) {
    super(props);
  }

  static getDerivedStateFromError(_: Error): State {
    // Update state so the next render will show the fallback UI.
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Log the error to an error reporting service
    console.error('Uncaught error:', error, errorInfo);
  }

  render() {
    // Fix: Correctly access this.state which is now properly typed via React.Component
    if (this.state.hasError) {
      return (
        <div className="flex items-center justify-center h-screen bg-gray-900 text-gray-300">
            <div className="text-center p-8 bg-gray-800 rounded-lg shadow-2xl border border-red-700 max-w-md">
                <AlertTriangleIcon className="w-16 h-16 text-red-500 mx-auto mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Something went wrong.</h1>
                <p className="text-gray-400">
                    An unexpected error has occurred. Please try refreshing the page.
                    If the problem persists, please check the console for more details.
                </p>
                <button
                    onClick={() => window.location.reload()}
                    className="mt-6 px-4 py-2 bg-cyan-600 text-white font-semibold rounded-md hover:bg-cyan-700 transition-colors"
                >
                    Refresh Page
                </button>
            </div>
        </div>
      );
    }

    // Fix: Correctly access this.props which is now properly typed via React.Component
    return this.props.children;
  }
}

export default ErrorBoundary;

