import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GraphData, AnalysisResult, NodeObject, NodeAnalysisResult } from './types';
import { parseEdgeList, parseGedcom } from './services/graphService';
import ControlPanel from './components/ControlPanel';
import GraphVisualizer from './components/GraphVisualizer';
import GraphLegend from './components/GraphLegend';
import { UploadIcon, GraphIcon } from './components/ui/Icons';
import { GoogleGenAI } from "@google/genai";

const GRAPH_WORKER_CODE = `
const bfs = (startNodeId, adjacencyList) => {
  const distances = new Map([[startNodeId, 0]]);
  const queue = [startNodeId];
  let maxDistance = 0;

  let head = 0;
  while(head < queue.length) {
    const currentNodeId = queue[head++];
    const currentDistance = distances.get(currentNodeId);

    if (currentDistance > maxDistance) {
        maxDistance = currentDistance;
    }

    const neighbors = adjacencyList.get(currentNodeId) || [];
    for (const neighborId of neighbors) {
      if (!distances.has(neighborId)) {
        distances.set(neighborId, currentDistance + 1);
        queue.push(neighborId);
      }
    }
  }

  return { distances, maxDistance };
};

const findShortestPath = (startId, endId, adjacencyList) => {
    if (startId === endId) return [startId];
    const queue = [[startId]];
    const visited = new Set([startId]);

    let head = 0;
    while(head < queue.length) {
        const path = queue[head++];
        const node = path[path.length - 1];

        for (const neighbor of adjacencyList.get(node) || []) {
            if (neighbor === endId) return [...path, neighbor];
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                queue.push([...path, neighbor]);
            }
        }
    }
    return null;
};

const findConnectedComponents = (graphData, adjacencyList) => {
    const components = [];
    const visited = new Set();

    for(const node of graphData.nodes) {
        if(!visited.has(node.id)) {
            const component = [];
            const queue = [node.id];
            visited.add(node.id);
            let head = 0;
            while(head < queue.length) {
                const u = queue[head++];
                component.push(u);
                for(const v of adjacencyList.get(u) || []) {
                    if(!visited.has(v)) {
                        visited.add(v);
                        queue.push(v);
                    }
                }
            }
            components.push(component);
        }
    }
    return components;
}

const calculateGraphDensity = (nodeCount, edgeCount) => {
    if (nodeCount < 2) return 0;
    return (2 * edgeCount) / (nodeCount * (nodeCount - 1));
};

const calculateAverageShortestPath = (componentNodeIds, adjacencyList) => {
    let totalDistanceSum = 0;
    const n = componentNodeIds.length;
    let reachablePairs = 0;

    if (n < 2) return 0;

    for (const startNodeId of componentNodeIds) {
        const { distances } = bfs(startNodeId, adjacencyList);
        for (const [endNodeId, d] of distances.entries()) {
            if (startNodeId !== endNodeId) {
                totalDistanceSum += d;
                reachablePairs++;
            }
        }
    }

    return reachablePairs > 0 ? totalDistanceSum / reachablePairs : 0;
};

const findArticulationPoints = (componentNodeIds, adjacencyList) => {
    const points = new Set();
    const visited = new Set();
    const discoveryTimes = new Map();
    const lowLinkValues = new Map();
    const parent = new Map();
    let time = 0;

    const dfs = (u) => {
        visited.add(u);
        discoveryTimes.set(u, time);
        lowLinkValues.set(u, time);
        time++;
        let children = 0;

        const neighbors = adjacencyList.get(u) || [];
        for (const v of neighbors) {
            if (v === parent.get(u)) continue;

            if (visited.has(v)) {
                lowLinkValues.set(u, Math.min(lowLinkValues.get(u), discoveryTimes.get(v)));
            } else {
                children++;
                parent.set(v, u);
                dfs(v);
                lowLinkValues.set(u, Math.min(lowLinkValues.get(u), lowLinkValues.get(v)));

                if (parent.get(u) === null && children > 1) {
                    points.add(u);
                }
                if (parent.get(u) !== null && lowLinkValues.get(v) >= discoveryTimes.get(u)) {
                    points.add(u);
                }
            }
        }
    };

    for (const nodeId of componentNodeIds) {
        if (!visited.has(nodeId)) {
            parent.set(nodeId, null);
            dfs(nodeId);
        }
    }

    return Array.from(points);
};

const calculateBetweennessCentrality = (componentNodeIds, adjacencyList) => {
    const centrality = new Map();
    for (const id of componentNodeIds) {
        centrality.set(id, 0);
    }

    for (const s of componentNodeIds) {
        const stack = [];
        const predecessors = new Map();
        const shortestPathCounts = new Map();
        const distances = new Map();

        for (const id of componentNodeIds) {
            predecessors.set(id, []);
            shortestPathCounts.set(id, 0);
            distances.set(id, -1);
        }

        shortestPathCounts.set(s, 1);
        distances.set(s, 0);
        const queue = [s];

        let head = 0;
        while (head < queue.length) {
            const v = queue[head++];
            stack.push(v);
            const neighbors = adjacencyList.get(v) || [];

            for (const w of neighbors) {
                if (distances.get(w) < 0) {
                    queue.push(w);
                    distances.set(w, distances.get(v) + 1);
                }
                if (distances.get(w) === distances.get(v) + 1) {
                    shortestPathCounts.set(w, shortestPathCounts.get(w) + shortestPathCounts.get(v));
                    predecessors.get(w).push(v);
                }
            }
        }

        const dependencies = new Map();
        for(const id of componentNodeIds) {
            dependencies.set(id, 0);
        }

        while (stack.length > 0) {
            const w = stack.pop();
            for (const v of predecessors.get(w)) {
                const dependency = shortestPathCounts.get(v) / shortestPathCounts.get(w) * (1 + dependencies.get(w));
                dependencies.set(v, dependencies.get(v) + dependency);
            }
            if (w !== s) {
                centrality.set(w, centrality.get(w) + dependencies.get(w));
            }
        }
    }

    return componentNodeIds
        .map(id => ({ node: {id}, value: centrality.get(id) / 2 }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 5);
};

const calculateDegreeCentrality = (graphData, adjacencyList) => {
    return graphData.nodes
        .map(node => ({
            node,
            value: (adjacencyList.get(node.id) || []).length,
        }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 5);
};

const calculateDegreeDistribution = (adjacencyList) => {
    const distribution = new Map();
    for (const neighbors of adjacencyList.values()) {
        const degree = neighbors.length;
        distribution.set(degree, (distribution.get(degree) || 0) + 1);
    }
    return Array.from(distribution.entries())
        .map(([degree, count]) => ({ degree, count }))
        .sort((a, b) => a.degree - b.degree);
};

const createMemoizedCounter = (map) => {
    const memo = new Map();
    const count = (nodeId) => {
        if (memo.has(nodeId)) {
            return memo.get(nodeId);
        }
        const relatedNodes = new Set();
        const directConnections = map.get(nodeId) || [];
        for (const connectedId of directConnections) {
            relatedNodes.add(connectedId);
            const indirect = count(connectedId);
            indirect.forEach(node => relatedNodes.add(node));
        }
        memo.set(nodeId, relatedNodes);
        return relatedNodes;
    };
    return count;
};

const calculateDescendantCentrality = (graphData) => {
    const childMap = new Map();
    graphData.links.forEach(link => {
        if (link.type === 'parent-child') {
            const parentId = typeof link.source === 'object' ? link.source.id : link.source;
            const childId = typeof link.target === 'object' ? link.target.id : link.target;
            if (!childMap.has(parentId)) childMap.set(parentId, []);
            childMap.get(parentId).push(childId);
        }
    });
    const countAllDescendants = createMemoizedCounter(childMap);
    return graphData.nodes
        .map(node => ({ node, value: countAllDescendants(node.id).size }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 5);
};

const calculateAncestorCentrality = (graphData) => {
    const parentMap = new Map();
    graphData.links.forEach(link => {
        if (link.type === 'parent-child') {
            const parentId = typeof link.source === 'object' ? link.source.id : link.source;
            const childId = typeof link.target === 'object' ? link.target.id : link.target;
            if (!parentMap.has(childId)) parentMap.set(childId, []);
            parentMap.get(childId).push(parentId);
        }
    });
    const countAllAncestors = createMemoizedCounter(parentMap);
    return graphData.nodes
        .map(node => ({ node, value: countAllAncestors(node.id).size }))
        .sort((a, b) => b.value - a.value)
        .slice(0, 5);
};

const calculateGenealogicalStructure = (componentNodeIds, graphData) => {
    if (componentNodeIds.length === 0) {
        return { averageGenerationWidth: 'N/A', averageLeafDepth: 'N/A', structureRatio: 'N/A' };
    }
    const componentNodeSet = new Set(componentNodeIds);
    const parentToChildMap = new Map();
    const childToParentMap = new Map();

    graphData.links.forEach(link => {
        if (link.type === 'parent-child') {
            const parentId = typeof link.source === 'object' ? link.source.id : link.source;
            const childId = typeof link.target === 'object' ? link.target.id : link.target;
            if (componentNodeSet.has(parentId) && componentNodeSet.has(childId)) {
                if (!parentToChildMap.has(parentId)) parentToChildMap.set(parentId, []);
                parentToChildMap.get(parentId).push(childId);
                if (!childToParentMap.has(childId)) childToParentMap.set(childId, []);
                childToParentMap.get(childId).push(parentId);
            }
        }
    });

    const roots = componentNodeIds.filter(id => !(childToParentMap.has(id) && childToParentMap.get(id).length > 0));
    if (roots.length === 0) { 
        if(componentNodeIds.length > 0) roots.push(componentNodeIds[0]);
        else return { averageGenerationWidth: 'N/A', averageLeafDepth: 'N/A', structureRatio: 'N/A' };
    }

    const generationCounts = new Map();
    const visitedBfs = new Set();
    const queue = roots.map(root => ({ nodeId: root, depth: 0 }));
    roots.forEach(r => visitedBfs.add(r));

    let head = 0;
    while(head < queue.length) {
        const { nodeId, depth } = queue[head++];
        generationCounts.set(depth, (generationCounts.get(depth) || 0) + 1);
        const children = parentToChildMap.get(nodeId) || [];
        for (const childId of children) {
            if (!visitedBfs.has(childId)) {
                visitedBfs.add(childId);
                queue.push({ nodeId: childId, depth: depth + 1 });
            }
        }
    }

    let avgWidth = 0;
    if (generationCounts.size > 0) {
        let totalNodesInGenerations = 0;
        for (const count of generationCounts.values()) {
            totalNodesInGenerations += count;
        }
        avgWidth = totalNodesInGenerations / generationCounts.size;
    }

    const leafDepths = [];
    const visitedDfs = new Set();
    const dfs = (nodeId, currentDepth) => {
        visitedDfs.add(nodeId);
        const children = parentToChildMap.get(nodeId) || [];
        const unvisitedChildren = children.filter(c => !visitedDfs.has(c));
        if (unvisitedChildren.length === 0) {
            leafDepths.push(currentDepth);
            return;
        }
        for (const childId of unvisitedChildren) {
            dfs(childId, currentDepth + 1);
        }
    };
    roots.forEach(root => dfs(root, 0));

    let avgDepth = 0;
    if (leafDepths.length > 0) {
        const sumOfDepths = leafDepths.reduce((sum, d) => sum + d, 0);
        avgDepth = sumOfDepths / leafDepths.length;
    }
    const ratio = avgWidth > 0 ? avgDepth / avgWidth : 0;

    return {
        averageGenerationWidth: avgWidth > 0 ? avgWidth.toFixed(2) : 'N/A',
        averageLeafDepth: avgDepth > 0 ? avgDepth.toFixed(2) : 'N/A',
        structureRatio: ratio > 0 ? ratio.toFixed(2) : 'N/A',
    };
};

const detectCommunities = (graphData, adjacencyList) => {
    const nodes = graphData.nodes.map(n => n.id);
    if (nodes.length === 0) return [];
    let communities = new Map();
    nodes.forEach(nodeId => communities.set(nodeId, nodeId));

    let changed = true;
    let iterations = 0;
    const maxIterations = 20;

    while (changed && iterations < maxIterations) {
        changed = false;
        iterations++;
        const shuffledNodes = nodes.slice().sort(() => Math.random() - 0.5);

        shuffledNodes.forEach(nodeId => {
            const neighbors = adjacencyList.get(nodeId) || [];
            if (neighbors.length === 0) return;
            const labelCounts = new Map();
            neighbors.forEach(neighborId => {
                const label = communities.get(neighborId);
                labelCounts.set(label, (labelCounts.get(label) || 0) + 1);
            });
            let maxCount = 0;
            let bestLabels = [];
            for (const [label, count] of labelCounts.entries()) {
                if (count > maxCount) {
                    maxCount = count;
                    bestLabels = [label];
                } else if (count === maxCount) {
                    bestLabels.push(label);
                }
            }
            const bestLabel = bestLabels[Math.floor(Math.random() * bestLabels.length)];
            if (communities.get(nodeId) !== bestLabel) {
                communities.set(nodeId, bestLabel);
                changed = true;
            }
        });
    }

    const finalCommunitiesMap = new Map();
    communities.forEach((communityId, nodeId) => {
        if (!finalCommunitiesMap.has(communityId)) {
            finalCommunitiesMap.set(communityId, []);
        }
        finalCommunitiesMap.get(communityId).push(nodeId);
    });

    const communitiesArray = Array.from(finalCommunitiesMap.values());
    communitiesArray.sort((a, b) => b.length - a.length);

    const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));
    return communitiesArray.map(community => 
        community.map(nodeId => nodeMap.get(nodeId)).filter(Boolean)
    );
};

const calculateLocalClusteringCoefficient = (nodeId, adjacencyList) => {
    const neighbors = adjacencyList.get(nodeId) || [];
    const k = neighbors.length;
    if (k < 2) return 0;
    const neighborSet = new Set(neighbors);
    let links = 0;
    for (const neighbor of neighbors) {
        const neighborNeighbors = adjacencyList.get(neighbor) || [];
        for (const n of neighborNeighbors) {
            if (neighborSet.has(n)) {
                links++;
            }
        }
    }
    return links / (k * (k - 1));
};

const analyzeGraph = (graphData, adjacencyList) => {
  const nodeCount = graphData.nodes.length;
  const edgeCount = graphData.links.length;
  const isGedcomGraph = graphData.links.some(l => l.type === 'parent-child' || l.type === 'marriage');
  const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));

  const components = findConnectedComponents(graphData, adjacencyList);
  const componentCount = components.length;

  const largestComponent = components.reduce((largest, current) => current.length > largest.length ? current : largest, []);
  const largestComponentSize = largestComponent.length;

  let diameter = 'N/A';
  let averageShortestPath = 'N/A';
  let articulationPoints = [];
  let betweennessCentrality = [];

  if (largestComponentSize > 1) {
    let maxEccentricity = 0;
    const componentAdjacencyList = new Map();
    largestComponent.forEach(nodeId => {
        componentAdjacencyList.set(nodeId, adjacencyList.get(nodeId) || []);
    });

    for (const nodeId of largestComponent) {
      const { maxDistance } = bfs(nodeId, componentAdjacencyList);
      if (maxDistance > maxEccentricity) {
        maxEccentricity = maxDistance;
      }
    }
    diameter = String(maxEccentricity);
    averageShortestPath = calculateAverageShortestPath(largestComponent, componentAdjacencyList).toFixed(2);

    const allArticulationPoints = findArticulationPoints(largestComponent, componentAdjacencyList);
    articulationPoints = allArticulationPoints
                            .slice(0, 5)
                            .map(id => nodeMap.get(id))
                            .filter(Boolean);

    betweennessCentrality = calculateBetweennessCentrality(largestComponent, componentAdjacencyList);
    betweennessCentrality.forEach(item => {
        item.node = nodeMap.get(item.node.id) || item.node;
    });
  }

  const centralityByConnections = calculateDegreeCentrality(graphData, adjacencyList);
  const degreeDistribution = calculateDegreeDistribution(adjacencyList);

  const baseResult = {
    nodeCount,
    edgeCount,
    componentCount,
    isConnected: componentCount === 1,
    graphDensity: calculateGraphDensity(nodeCount, edgeCount).toFixed(4),
    largestComponentSize,
    diameter,
    averageShortestPath,
    articulationPoints,
    centralityByConnections,
    betweennessCentrality,
    degreeDistribution,
  };

  if (isGedcomGraph) {
    return {
      ...baseResult,
      centralityByDescendants: calculateDescendantCentrality(graphData),
      centralityByAncestors: calculateAncestorCentrality(graphData),
      ...calculateGenealogicalStructure(largestComponent, graphData),
    };
  }
  return baseResult;
};

self.onmessage = (event) => {
  try {
    const { type, graphData, nodeId, startId, endId } = event.data;
    const adjacencyList = new Map();
    graphData.nodes.forEach(node => adjacencyList.set(node.id, []));
    graphData.links.forEach(({ source, target }) => {
        const sourceId = typeof source === 'object' && source !== null ? source.id : source;
        const targetId = typeof target === 'object' && target !== null ? target.id : target;
        if (!adjacencyList.has(sourceId)) adjacencyList.set(sourceId, []);
        if (!adjacencyList.has(targetId)) adjacencyList.set(targetId, []);
        adjacencyList.get(sourceId).push(targetId);
        adjacencyList.get(targetId).push(sourceId);
    });

    if (type === 'analyze') {
        const result = analyzeGraph(graphData, adjacencyList);
        self.postMessage({ type: 'analysis_success', result });
    } else if (type === 'detectCommunities') {
        const result = detectCommunities(graphData, adjacencyList);
        self.postMessage({ type: 'communities_success', result });
    } else if (type === 'findPath') {
        const path = findShortestPath(startId, endId, adjacencyList);
        self.postMessage({ type: 'path_success', path });
    } else if (type === 'analyzeNode' && nodeId) {
        const neighbors = adjacencyList.get(nodeId) || [];
        const degree = neighbors.length;
        const clustering = calculateLocalClusteringCoefficient(nodeId, adjacencyList);
        const { distances, maxDistance } = bfs(nodeId, adjacencyList);
        let totalDist = 0;
        let count = 0;
        distances.forEach((dist, id) => {
            if (id !== nodeId) {
                totalDist += dist;
                count++;
            }
        });
        const avgDist = count > 0 ? totalDist / count : 0;
        const result = {
            id: nodeId,
            degree,
            clusteringCoefficient: clustering,
            eccentricity: maxDistance,
            averageDistance: avgDist,
            reachableNodes: count + 1 
        };
        self.postMessage({ type: 'node_analysis_success', result });
    }
  } catch (error) {
    self.postMessage({ type: 'error', error: error.message || 'An unknown worker error occurred.' });
  }
};
`;

const App: React.FC = () => {
  const [graphData, setGraphData] = useState<GraphData | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [isDetectingCommunities, setIsDetectingCommunities] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [isGedcom, setIsGedcom] = useState<boolean>(false);
  const [statusMessage, setStatusMessage] = useState<string>('');

  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [isGeneratingAi, setIsGeneratingAi] = useState<boolean>(false);

  const [shortestPath, setShortestPath] = useState<string[] | null>(null);

  const [rawFileContent, setRawFileContent] = useState<string | null>(null);
  const [isAdvancedMode, setIsAdvancedMode] = useState<boolean>(false);

  const [selectedNode, setSelectedNode] = useState<NodeObject | null>(null);
  const [selectedNodeStats, setSelectedNodeStats] = useState<NodeAnalysisResult | null>(null);
  const [hoveredNode, setHoveredNode] = useState<NodeObject | null>(null);
  const fgRef = useRef<any>(null);
  const workerRef = useRef<Worker | null>(null);

  useEffect(() => {
    let worker: Worker | null = null;
    let objectUrl: string | null = null;

    const createWorker = async () => {
      try {
        const blob = new Blob([GRAPH_WORKER_CODE], { type: 'application/javascript' });
        objectUrl = URL.createObjectURL(blob);
        worker = new Worker(objectUrl);
        workerRef.current = worker;

        worker.addEventListener('message', (event) => {
          const { type, result, path, error: workerError } = event.data;

          if (type === 'analysis_success') {
            setIsAnalyzing(false);
            setAnalysisResult(result);
            setStatusMessage('Analysis complete.');
          } else if (type === 'communities_success') {
            setIsDetectingCommunities(false);
            setAnalysisResult(prev => prev ? { ...prev, communities: result } : null);
            setStatusMessage('Communities detected.');
          } else if (type === 'node_analysis_success') {
             setSelectedNodeStats(result);
          } else if (type === 'path_success') {
            setShortestPath(path);
            if (!path) setStatusMessage('No path found between nodes.');
            else setStatusMessage(`Shortest path found: ${path.length} steps.`);
          } else if (type === 'error') {
            setIsAnalyzing(false);
            setIsDetectingCommunities(false);
            setError(workerError || 'Worker error.');
          }
        });
      } catch (err) {
        setError(`Worker init failed: ${err instanceof Error ? err.message : "Unknown"}`);
      }
    };
    createWorker();
    return () => {
      worker?.terminate();
      if (objectUrl) URL.revokeObjectURL(objectUrl);
    };
  }, []);

  const clearAnalysis = () => {
    setAnalysisResult(null);
    setSelectedNode(null);
    setSelectedNodeStats(null);
    setHoveredNode(null);
    setAiSummary(null);
    setShortestPath(null);
    setIsAnalyzing(false);
    setIsDetectingCommunities(false);
  };

  const resetGraphState = () => {
    setGraphData(null);
    clearAnalysis();
    setIsGedcom(false);
    setRawFileContent(null);
    setIsAdvancedMode(false);
  };

  const handleToggleAdvancedMode = useCallback(() => {
      if (!rawFileContent || !isGedcom) return;
      const newMode = !isAdvancedMode;
      setIsAdvancedMode(newMode);
      clearAnalysis(); 
      try {
          const data = parseGedcom(rawFileContent, newMode);
          setGraphData(data);
      } catch (err) {
          setError(err instanceof Error ? err.message : 'Failed to re-parse file.');
      }
  }, [rawFileContent, isGedcom, isAdvancedMode]);

  const handleFileSelect = useCallback((file: File) => {
    setError(null);
    resetGraphState();
    if (!file) return;
    const fileExtension = file.name.split('.').pop()?.toLowerCase();
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        setRawFileContent(content);
        const isGedcomFile = fileExtension === 'ged';
        setIsGedcom(isGedcomFile);
        const data = isGedcomFile ? parseGedcom(content, false) : parseEdgeList(content);
        setGraphData(data);
        setStatusMessage(`Loaded ${file.name}.`);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Parse error.');
      }
    };
    reader.readAsText(file);
  }, []);

  const handleSampleSelect = useCallback((content: string, type: 'ged' | 'txt', name: string) => {
    setError(null);
    resetGraphState();
    try {
        setRawFileContent(content);
        setIsGedcom(type === 'ged');
        const data = type === 'ged' ? parseGedcom(content, false) : parseEdgeList(content);
        setGraphData(data);
        setStatusMessage(`Loaded ${name}.`);
    } catch (err) {
        setError('Sample load failed.');
    }
  }, []);

  const handleAnalyze = useCallback(() => {
    if (!graphData || !workerRef.current) return;
    clearAnalysis();
    setIsAnalyzing(true);
    workerRef.current.postMessage({ type: 'analyze', graphData });
  }, [graphData]);

  const handleDetectCommunities = useCallback(() => {
    if (!graphData || !workerRef.current) return;
    setIsDetectingCommunities(true);
    workerRef.current.postMessage({ type: 'detectCommunities', graphData });
  }, [graphData]);

  const handleNodeClick = useCallback((node: NodeObject, event?: MouseEvent) => {
    if (event?.shiftKey && selectedNode && node.id !== selectedNode.id && graphData && workerRef.current) {
        workerRef.current.postMessage({ 
            type: 'findPath', 
            graphData, 
            startId: selectedNode.id, 
            endId: node.id 
        });
        return;
    }

    setSelectedNode(node);
    setSelectedNodeStats(null);
    setShortestPath(null); 
    if (graphData && workerRef.current) {
        workerRef.current.postMessage({ type: 'analyzeNode', graphData, nodeId: node.id });
    }
  }, [graphData, selectedNode]);

  const handleGenerateAiInsights = async () => {
    if (!analysisResult) return;
    setIsGeneratingAi(true);
    setAiSummary(null);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Analyze this graph network data and provide a concise, professional summary in Hebrew. 
        Focus on structure, connectivity, and key influencers. Mention if it looks like a genealogy tree or a general network.
        Data: ${JSON.stringify({
            nodes: analysisResult.nodeCount,
            edges: analysisResult.edgeCount,
            density: analysisResult.graphDensity,
            isConnected: analysisResult.isConnected,
            diameter: analysisResult.diameter,
            topNodes: analysisResult.centralityByConnections?.map(c => c.node.name || c.node.id),
            communitiesFound: analysisResult.communities?.length
        })}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });
        setAiSummary(response.text || "No insights generated.");
    } catch (err) {
        console.error(err);
        setAiSummary("שגיאה ביצירת תובנות. נסה שוב מאוחר יותר.");
    } finally {
        setIsGeneratingAi(false);
    }
  };

  const handleClearSelection = useCallback(() => {
      setSelectedNode(null);
      setSelectedNodeStats(null);
      setShortestPath(null);
  }, []);

  return (
    <div className="h-screen flex flex-col font-sans bg-gray-900 text-gray-200 overflow-hidden">
      <header className="bg-gray-800 bg-opacity-50 backdrop-blur-sm shadow-lg p-4 z-10 border-b border-gray-700 flex-shrink-0">
        <div className="container mx-auto flex items-center gap-4">
          <GraphIcon className="w-8 h-8 text-cyan-400" />
          <h1 className="text-2xl font-bold tracking-tight text-white">
            Graph Analysis Tool
          </h1>
        </div>
      </header>

      <main className="flex-grow flex flex-col md:flex-row container mx-auto p-4 gap-4 min-h-0">
        {/* Control Panel: On mobile, max height is 40% of the screen */}
        <div className="w-full md:w-1/3 lg:w-1/4 flex-shrink-0 max-h-[40vh] md:max-h-none h-auto md:h-full overflow-hidden flex flex-col">
          <ControlPanel
            onFileSelect={handleFileSelect}
            onAnalyze={handleAnalyze}
            onDetectCommunities={handleDetectCommunities}
            onSampleSelect={handleSampleSelect}
            analysisResult={analysisResult}
            isAnalyzing={isAnalyzing}
            isDetectingCommunities={isDetectingCommunities}
            error={error}
            hasGraphData={!!graphData}
            graphData={graphData}
            selectedNode={selectedNode}
            selectedNodeStats={selectedNodeStats}
            onNodeSelect={handleNodeClick}
            onClearSelection={handleClearSelection}
            isAdvancedMode={isAdvancedMode}
            onToggleAdvancedMode={handleToggleAdvancedMode}
            isGedcom={isGedcom}
            onGenerateAiInsights={handleGenerateAiInsights}
            aiSummary={aiSummary}
            isGeneratingAi={isGeneratingAi}
          />
        </div>

        {/* Graph Visualizer: Takes remaining space, but at least 400px on mobile */}
        <div className="flex-grow min-h-[400px] md:min-h-0 bg-gray-800 rounded-lg shadow-2xl overflow-hidden relative border border-gray-700 h-full">
          {graphData ? (
            <>
              <GraphVisualizer
                fgRef={fgRef}
                graphData={graphData}
                onNodeClick={handleNodeClick}
                onBackgroundClick={handleClearSelection}
                hoveredNode={hoveredNode}
                onNodeHover={setHoveredNode}
                selectedNode={selectedNode}
                analysisResult={analysisResult}
                shortestPath={shortestPath}
              />
              <GraphLegend isGedcom={isGedcom} isAdvancedMode={isAdvancedMode} />

              {shortestPath && (
                <div className="absolute bottom-4 left-4 right-4 bg-gray-900 bg-opacity-90 border border-cyan-500/50 p-2 rounded text-xs text-cyan-200 backdrop-blur-sm animate-pulse">
                    Path Highlighted: {shortestPath.length} nodes involved.
                </div>
              )}
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-center p-8">
              <UploadIcon className="w-24 h-24 text-gray-600 mb-6" />
              <h2 className="text-2xl font-semibold text-gray-300">Welcome to the Graph Analyzer</h2>
              <p className="mt-2 text-gray-400 max-w-md">
                Upload a file to start visualizing your network.
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState, useMemo } from 'react';
import { AnalysisResult, NodeObject, CentralityResult, DegreeDistributionResult, GraphData, NodeAnalysisResult } from '../types';
import Button from './ui/Button';
import Card from './ui/Card';
import Spinner from './ui/Spinner';
import SampleDataSelector from './SampleDataSelector';
import Tooltip from './ui/Tooltip';
import { InfoIcon, AlertTriangleIcon, UploadIcon, BarChart2Icon, XCircleIcon, ChevronRightIcon, UsersIcon, SearchIcon, SparklesIcon } from './ui/Icons';

interface ControlPanelProps {
  onFileSelect: (file: File) => void;
  onAnalyze: () => void;
  onDetectCommunities: () => void;
  onSampleSelect: (content: string, type: 'ged' | 'txt', name: string) => void;
  analysisResult: AnalysisResult | null;
  isAnalyzing: boolean;
  isDetectingCommunities: boolean;
  error: string | null;
  hasGraphData: boolean;
  graphData: GraphData | null;
  selectedNode: NodeObject | null;
  selectedNodeStats: NodeAnalysisResult | null;
  onNodeSelect: (node: NodeObject, event?: any) => void;
  onClearSelection: () => void;
  isAdvancedMode: boolean;
  onToggleAdvancedMode: () => void;
  isGedcom: boolean;
  onGenerateAiInsights: () => void;
  aiSummary: string | null;
  isGeneratingAi: boolean;
}

const StatItem: React.FC<{ label: string; value: React.ReactNode; tooltip?: string }> = ({ label, value, tooltip }) => (
    <div className="flex justify-between items-center py-2.5 border-b border-gray-700 last:border-b-0">
        <span className="text-sm text-gray-400 flex items-center gap-1.5">
            {label}
            {tooltip && (
                <Tooltip content={tooltip}>
                    <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                </Tooltip>
            )}
        </span>
        <span className="text-base font-semibold text-white">{String(value)}</span>
    </div>
);

const RankedStatItem: React.FC<{ label: string; items: CentralityResult[]; emptyText?: string; tooltip?: string }> = ({ label, items, emptyText = "Not applicable", tooltip }) => (
     <div className="py-2.5 border-b border-gray-700 last:border-b-0">
        <div className="flex justify-between items-center mb-1">
            <span className="text-sm text-gray-400 flex items-center gap-1.5">
                {label}
                {tooltip && (
                     <Tooltip content={tooltip}>
                        <InfoIcon className="w-4 h-4 text-gray-500 cursor-help" />
                    </Tooltip>
                )}
            </span>
        </div>
        {items && items.length > 0 && items.some(i => i.value > 0) ? (
             <ol className="mt-1.5 pl-1 space-y-1">
                {items.map((item, index) => item.value > 0 && (
                    <li key={item.node.id} className="text-sm text-gray-300 bg-gray-700 bg-opacity-50 px-2 py-1 rounded flex justify-between items-center" title={item.node.name || item.node.id}>
                       <span className="truncate pr-2">{index + 1}. {item.node.name || item.node.id}</span>
                       <span className="font-semibold text-cyan-400 flex-shrink-0">{item.value.toFixed(2)}</span>
                    </li>
                ))}
            </ol>
        ) : (
             <p className="mt-1 text-sm text-right text-gray-500">{emptyText}</p>
        )}
    </div>
);

const CommunityListStatItem: React.FC<{ 
  label: string; 
  communities: NodeObject[][]; 
  onNodeSelect: (node: NodeObject) => void; 
  tooltip?: string 
}> = ({ label, communities, onNodeSelect, tooltip }) => {
    const topCommunities = communities.slice(0, 5); 
    return (
        <div className="py-2.5 border-b border-gray-700 last:border-b-0">
