                        </Tooltip>
                    )}
                </span>
                <span className="text-base font-semibold text-white">{communities.length} found</span>
            </div>
            {topCommunities.length > 0 ? (
                <div className="mt-1.5 pl-1 space-y-2">
                    {topCommunities.map((community, index) => (
                        <details key={index} className="bg-gray-700 bg-opacity-50 px-2 py-1.5 rounded group">
                            <summary className="text-sm text-gray-300 cursor-pointer list-none flex justify-between items-center font-semibold">
