};

const ControlPanel: React.FC<ControlPanelProps> = ({
  onFileSelect,
  onAnalyze,
  onDetectCommunities,
  onSampleSelect,
  analysisResult,
  isAnalyzing,
  isDetectingCommunities,
  error,
  hasGraphData,
  graphData,
  selectedNode,
  selectedNodeStats,
  onNodeSelect,
  onClearSelection,
  isAdvancedMode,
  onToggleAdvancedMode,
  isGedcom,
  onGenerateAiInsights,
  aiSummary,
  isGeneratingAi
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredNodes = useMemo(() => {
    if (!searchQuery.trim() || !graphData) return [];
    const query = searchQuery.toLowerCase();
    return graphData.nodes.filter(node => 
        (node.name && node.name.toLowerCase().includes(query)) || 
        node.id.toLowerCase().includes(query)
    ).slice(0, 10);
  }, [searchQuery, graphData]);

  const getSelectedNodeNeighbors = () => {
    if (!selectedNode || !graphData) return [];
    const neighbors = new Set<string>();
    graphData.links.forEach(link => {
        const sourceId = typeof link.source === 'object' ? (link.source as NodeObject).id : link.source;
        const targetId = typeof link.target === 'object' ? (link.target as NodeObject).id : link.target;
        if(sourceId === selectedNode.id) neighbors.add(targetId);
        if(targetId === selectedNode.id) neighbors.add(sourceId);
    });
    const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));
    return Array.from(neighbors).map(id => nodeMap.get(id)).filter(Boolean) as NodeObject[];
  };

  const neighbors = getSelectedNodeNeighbors();
  const isLoading = isAnalyzing || isDetectingCommunities;

  return (
    <Card className="flex flex-col h-full max-h-full overflow-hidden">
      <div className="flex-grow overflow-y-auto p-5 space-y-6">
          {hasGraphData && (
              <div>
                <h2 className="text-xl font-bold text-white mb-3">Search</h2>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <SearchIcon className="h-4 w-4 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        className="block w-full pl-10 pr-8 py-2 border border-gray-600 rounded-md leading-5 bg-gray-700 text-gray-300 placeholder-gray-500 focus:outline-none focus:bg-gray-600 focus:border-cyan-500 sm:text-sm transition duration-150 ease-in-out"
                        placeholder="Search by name or ID..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                {searchQuery && (
                    <div className="mt-2 bg-gray-800 border border-gray-700 rounded-md shadow-lg max-h-60 overflow-y-auto relative z-20">
                        {filteredNodes.length > 0 ? (
                            <ul className="py-1">
                                {filteredNodes.map(node => (
                                    <li key={node.id}>
                                        <button
                                            className="w-full text-left px-4 py-2 text-sm text-gray-300 hover:bg-gray-700 hover:text-white flex items-center justify-between"
                                            onClick={() => { onNodeSelect(node); setSearchQuery(''); }}
                                        >
                                            <span className="truncate">{node.name || node.id}</span>
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <div className="px-4 py-3 text-sm text-gray-500">No matching nodes found.</div>
                        )}
                    </div>
                )}
              </div>
          )}

          <div>
            <h2 className="text-xl font-bold text-white mb-3">Controls</h2>
            <div className="flex flex-col gap-3">
                <input
                    type="file"
                    ref={fileInputRef}
                    onChange={(e) => e.target.files?.[0] && onFileSelect(e.target.files[0])}
                    className="hidden"
                    accept=".ged,.txt"
                />
                <Button onClick={() => fileInputRef.current?.click()} icon={<UploadIcon />}>
                    Upload Graph File
                </Button>

                {isGedcom && (
                    <div className="flex items-center justify-between bg-gray-700 bg-opacity-30 p-2 rounded-md border border-gray-600">
                        <div className="flex flex-col">
                            <span className="text-sm font-semibold text-gray-200">Advanced Mode</span>
                        </div>
                        <button
                            onClick={onToggleAdvancedMode}
                            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                                isAdvancedMode ? 'bg-cyan-600' : 'bg-gray-600'
                            }`}
                        >
                            <span className={`${isAdvancedMode ? 'translate-x-6' : 'translate-x-1'} inline-block h-4 w-4 transform rounded-full bg-white transition-transform`} />
                        </button>
                    </div>
                )}

                <Button onClick={onAnalyze} disabled={!hasGraphData || isLoading} icon={isAnalyzing ? <Spinner /> : <BarChart2Icon />}>
                    {isAnalyzing ? 'Analyzing...' : 'Run Analysis'}
                </Button>
                <Button onClick={onDetectCommunities} disabled={!analysisResult || isLoading} icon={isDetectingCommunities ? <Spinner /> : <UsersIcon />}>
                    {isDetectingCommunities ? 'Detecting...' : 'Detect Communities'}
                </Button>
            </div>
        </div>
        <div>
            <h2 className="text-xl font-bold text-white mb-3">Sample Datasets</h2>
            <SampleDataSelector onSelect={onSampleSelect} />
        </div>

        {selectedNode && (
          <div className="mt-6 pt-6 border-t border-gray-700">
              <div className="flex justify-between items-center mb-2">
                  <h2 className="text-xl font-bold text-white">Selected Node</h2>
                  <button onClick={onClearSelection} className="text-gray-500 hover:text-white">
                      <XCircleIcon className="w-6 h-6" />
                  </button>
              </div>
              <div className="bg-gray-700 bg-opacity-50 p-3 rounded-md">
                  <h3 className="font-bold text-cyan-400 truncate text-lg" title={selectedNode.name || selectedNode.id}>
                      {selectedNode.name || selectedNode.id}
                  </h3>
                  <div className="text-[10px] text-gray-400 mb-2 uppercase font-mono">Shift+Click another node to find path</div>

                  <div className="space-y-1">
                     <StatItem label="Degree" value={neighbors.length} />
                     {selectedNodeStats && (
                        <>
                          <StatItem label="Reachable" value={selectedNodeStats.reachableNodes} />
                          <StatItem label="Avg. Distance" value={selectedNodeStats.averageDistance.toFixed(2)} />
                        </>
                     )}
                  </div>
                  {neighbors.length > 0 && (
                      <div className="mt-3 pt-3 border-t border-gray-600">
                          <h4 className="text-xs font-semibold uppercase text-gray-500 mb-1">Neighbors</h4>
                          <ul className="max-h-32 overflow-y-auto space-y-1">
                              {neighbors.map(n => (
                                  <li key={n.id}>
                                      <button onClick={() => onNodeSelect(n)} className="w-full text-left text-xs text-gray-300 hover:text-cyan-400 bg-gray-600/30 px-2 py-1 rounded truncate">
                                          {n.name || n.id}
                                      </button>
                                  </li>
                              ))}
                          </ul>
                      </div>
                  )}
              </div>
          </div>
        )}

        <div className="mt-6 pt-6 border-t border-gray-700 space-y-4">
          <div>
              <div className="flex justify-between items-center mb-3">
                  <h2 className="text-xl font-bold text-white">Analysis Results</h2>
                  {analysisResult && (
                      <button 
                          onClick={onGenerateAiInsights} 
                          disabled={isGeneratingAi}
                          className="text-cyan-400 hover:text-cyan-300 disabled:text-gray-600 transition-colors flex items-center gap-1.5 text-sm font-semibold"
                      >
                          {isGeneratingAi ? <Spinner /> : <SparklesIcon className="w-4 h-4" />}
                          AI Insight
                      </button>
                  )}
              </div>

              {aiSummary && (
                  <div className="mb-4 bg-gradient-to-br from-cyan-900/40 to-purple-900/40 border border-cyan-500/30 p-4 rounded-lg shadow-inner text-sm text-cyan-100 leading-relaxed italic relative overflow-hidden group">
                      <div className="absolute top-0 right-0 p-1 opacity-20 group-hover:opacity-100 transition-opacity">
                          <SparklesIcon className="w-5 h-5 text-cyan-400" />
                      </div>
                      {aiSummary}
                  </div>
              )}

              {analysisResult ? (
                <div className="space-y-1">
                    <StatItem label="Nodes" value={analysisResult.nodeCount} />
                    <StatItem label="Edges" value={analysisResult.edgeCount} />
                    <StatItem label="Density" value={analysisResult.graphDensity} />
                    <StatItem label="Is Connected" value={analysisResult.isConnected ? 'Yes' : 'No'} />
                    <StatItem label="Components" value={analysisResult.componentCount} />
                    <StatItem label="Diameter" value={analysisResult.diameter} />

                    {analysisResult.centralityByConnections && <RankedStatItem label="Top Centrality" items={analysisResult.centralityByConnections} />}
                    {analysisResult.communities && <CommunityListStatItem label="Groups" communities={analysisResult.communities} onNodeSelect={onNodeSelect} />}
                </div>
              ) : (
                <div className="text-center py-8 text-gray-500">
                  <p>Run analysis to see results.</p>
                </div>
              )}
          </div>
        </div>
      </div>
    </Card>
  );
};

