```
function findArticulationPoints(
    componentNodeIds: string[],
    adjacencyList: Map<string, string[]>
): string[] {
    const articulationPoints = new Set<string>();
    const visited = new Set<string>();
    const discoveryTimes = new Map<string, number>();
    const lowLinkValues = new Map<string, number>();
    let time = 0;

    const dfs = (
        nodeId: string,
        parentId: string | null = null
    ): void => {
        visited.add(nodeId);
        discoveryTimes.set(nodeId, time++);
        lowLinkValues.set(nodeId, discoveryTimes.get(nodeId)!);
        let childrenCount = 0;

        for (const neighborId of adjacencyList.get(nodeId) || []) {
            if (neighborId === parentId) continue;

            if (!visited.has(neighborId)) {
                childrenCount++;
                dfs(neighborId, nodeId);
                lowLinkValues.set(
                    nodeId,
                    Math.min(
                        lowLinkValues.get(nodeId)!,
                        lowLinkValues.get(neighborId)!
                    )
                );

                if (
                    parentId !== null &&
                    lowLinkValues.get(neighborId)! >=
                        discoveryTimes.get(nodeId)!
                ) {
                    articulationPoints.add(nodeId);
                }
            } else {
                lowLinkValues.set(
                    nodeId,
                    Math.min(
                        lowLinkValues.get(nodeId)!,
                        discoveryTimes.get(neighborId)!
                    )
                );
            }
        }

        if (parentId === null && childrenCount > 1) {
            articulationPoints.add(nodeId);
        }
    };

    for (const nodeId of componentNodeIds) {
        if (!visited.has(nodeId)) {
            dfs(nodeId);
        }
    }

    return Array.from(articulationPoints);
}
```


