  const [isAdvancedMode, setIsAdvancedMode] = useState<boolean>(false);

  const [selectedNode, setSelectedNode] = useState<NodeObject | null>(null);
  const [selectedNodeStats, setSelectedNodeStats] = useState<NodeAnalysisResult | null>(null);
  const [hoveredNode, setHoveredNode] = useState<NodeObject | null>(null);
  const fgRef = useRef<any>(null);
  const workerRef = useRef<Worker | null>(null);

  useEffect(() => {
    let worker: Worker | null = null;
    let objectUrl: string | null = null;

    const createWorker = async () => {
      try {
        const blob = new Blob([GRAPH_WORKER_CODE], { type: 'application/javascript' });
        objectUrl = URL.createObjectURL(blob);
        worker = new Worker(objectUrl);
        workerRef.current = worker;

        worker.addEventListener('message', (event) => {
          const { type, result, path, error: workerError } = event.data;

          if (type === 'analysis_success') {
            setIsAnalyzing(false);
            setAnalysisResult(result);
            setStatusMessage('Analysis complete.');
          } else if (type === 'communities_success') {
            setIsDetectingCommunities(false);
            setAnalysisResult(prev => prev ? { ...prev, communities: result } : null);
            setStatusMessage('Communities detected.');
          } else if (type === 'node_analysis_success') {
             setSelectedNodeStats(result);
          } else if (type === 'path_success') {
            setShortestPath(path);
            if (!path) setStatusMessage('No path found between nodes.');
            else setStatusMessage(`Shortest path found: ${path.length} steps.`);
          } else if (type === 'error') {
            setIsAnalyzing(false);
            setIsDetectingCommunities(false);
            setError(workerError || 'Worker error.');
          }
        });
      } catch (err) {
        setError(`Worker init failed: ${err instanceof Error ? err.message : "Unknown"}`);
      }
    };
    createWorker();
    return () => {
      worker?.terminate();
      if (objectUrl) URL.revokeObjectURL(objectUrl);
    };
  }, []);

  const clearAnalysis = () => {
    setAnalysisResult(null);
    setSelectedNode(null);
    setSelectedNodeStats(null);
    setHoveredNode(null);
    setAiSummary(null);
    setShortestPath(null);
    setIsAnalyzing(false);
    setIsDetectingCommunities(false);
  };

  const resetGraphState = () => {
    setGraphData(null);
    clearAnalysis();
    setIsGedcom(false);
    setRawFileContent(null);
    setIsAdvancedMode(false);
  };

  const handleToggleAdvancedMode = useCallback(() => {
      if (!rawFileContent || !isGedcom) return;
      const newMode = !isAdvancedMode;
      setIsAdvancedMode(newMode);
      clearAnalysis(); 
      try {
          const data = parseGedcom(rawFileContent, newMode);
          setGraphData(data);
      } catch (err) {
          setError(err instanceof Error ? err.message : 'Failed to re-parse file.');
      }
  }, [rawFileContent, isGedcom, isAdvancedMode]);

  const handleFileSelect = useCallback((file: File) => {
    setError(null);
    resetGraphState();
    if (!file) return;
    const fileExtension = file.name.split('.').pop()?.toLowerCase();
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        setRawFileContent(content);
        const isGedcomFile = fileExtension === 'ged';
        setIsGedcom(isGedcomFile);
        const data = isGedcomFile ? parseGedcom(content, false) : parseEdgeList(content);
        setGraphData(data);
        setStatusMessage(`Loaded ${file.name}.`);
      } catch (err) {
        setError(err instanceof Error ? err.message : 'Parse error.');
      }
    };
    reader.readAsText(file);
  }, []);

  const handleSampleSelect = useCallback((content: string, type: 'ged' | 'txt', name: string) => {
    setError(null);
    resetGraphState();
    try {
        setRawFileContent(content);
        setIsGedcom(type === 'ged');
        const data = type === 'ged' ? parseGedcom(content, false) : parseEdgeList(content);
        setGraphData(data);
        setStatusMessage(`Loaded ${name}.`);
    } catch (err) {
        setError('Sample load failed.');
    }
  }, []);

  const handleAnalyze = useCallback(() => {
    if (!graphData || !workerRef.current) return;
    clearAnalysis();
    setIsAnalyzing(true);
    workerRef.current.postMessage({ type: 'analyze', graphData });
  }, [graphData]);

  const handleDetectCommunities = useCallback(() => {
    if (!graphData || !workerRef.current) return;
    setIsDetectingCommunities(true);
    workerRef.current.postMessage({ type: 'detectCommunities', graphData });
  }, [graphData]);

  const handleNodeClick = useCallback((node: NodeObject, event?: MouseEvent) => {
    if (event?.shiftKey && selectedNode && node.id !== selectedNode.id && graphData && workerRef.current) {
        workerRef.current.postMessage({ 
            type: 'findPath', 
            graphData, 
            startId: selectedNode.id, 
            endId: node.id 
        });
        return;
    }

    setSelectedNode(node);
    setSelectedNodeStats(null);
    setShortestPath(null); 
    if (graphData && workerRef.current) {
        workerRef.current.postMessage({ type: 'analyzeNode', graphData, nodeId: node.id });
    }
  }, [graphData, selectedNode]);

  const handleGenerateAiInsights = async () => {
    if (!analysisResult) return;
    setIsGeneratingAi(true);
    setAiSummary(null);
    try {
        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
        const prompt = `Analyze this graph network data and provide a concise, professional summary in Hebrew. 
        Focus on structure, connectivity, and key influencers. Mention if it looks like a genealogy tree or a general network.
        Data: ${JSON.stringify({
            nodes: analysisResult.nodeCount,
            edges: analysisResult.edgeCount,
            density: analysisResult.graphDensity,
            isConnected: analysisResult.isConnected,
            diameter: analysisResult.diameter,
            topNodes: analysisResult.centralityByConnections?.map(c => c.node.name || c.node.id),
            communitiesFound: analysisResult.communities?.length
        })}`;

        const response = await ai.models.generateContent({
            model: 'gemini-3-pro-preview',
            contents: prompt
        });
        setAiSummary(response.text || "No insights generated.");
    } catch (err) {
        console.error(err);
        setAiSummary("שגיאה ביצירת תובנות. נסה שוב מאוחר יותר.");
    } finally {
        setIsGeneratingAi(false);
    }
  };

  const handleClearSelection = useCallback(() => {
      setSelectedNode(null);
      setSelectedNodeStats(null);
      setShortestPath(null);
  }, []);

  return (
    <div className="h-screen flex flex-col font-sans bg-gray-900 text-gray-200 overflow-hidden">
      <header className="bg-gray-800 bg-opacity-50 backdrop-blur-sm shadow-lg p-4 z-10 border-b border-gray-700 flex-shrink-0">
        <div className="container mx-auto flex items-center gap-4">
          <GraphIcon className="w-8 h-8 text-cyan-400" />
          <h1 className="text-2xl font-bold tracking-tight text-white">
            Graph Analysis Tool
          </h1>
        </div>
      </header>

      <main className="flex-grow flex flex-col md:flex-row container mx-auto p-4 gap-4 min-h-0">
        <div className="w-full md:w-1/3 lg:w-1/4 flex-shrink-0 max-h-[40vh] md:max-h-none h-auto md:h-full overflow-hidden flex flex-col">
          <ControlPanel
            onFileSelect={handleFileSelect}
            onAnalyze={handleAnalyze}
            onDetectCommunities={handleDetectCommunities}
            onSampleSelect={handleSampleSelect}
            analysisResult={analysisResult}
            isAnalyzing={isAnalyzing}
            isDetectingCommunities={isDetectingCommunities}
            error={error}
            hasGraphData={!!graphData}
            graphData={graphData}
            selectedNode={selectedNode}
            selectedNodeStats={selectedNodeStats}
            onNodeSelect={handleNodeClick}
            onClearSelection={handleClearSelection}
            isAdvancedMode={isAdvancedMode}
            onToggleAdvancedMode={handleToggleAdvancedMode}
            isGedcom={isGedcom}
            onGenerateAiInsights={handleGenerateAiInsights}
            aiSummary={aiSummary}
            isGeneratingAi={isGeneratingAi}
          />
        </div>

        <div className="flex-grow min-h-[400px] md:min-h-0 bg-gray-800 rounded-lg shadow-2xl overflow-hidden relative border border-gray-700 h-full">
          {graphData ? (
            <>
              <GraphVisualizer
                fgRef={fgRef}
                graphData={graphData}
                onNodeClick={handleNodeClick}
                onBackgroundClick={handleClearSelection}
                hoveredNode={hoveredNode}
                onNodeHover={setHoveredNode}
                selectedNode={selectedNode}
                analysisResult={analysisResult}
                shortestPath={shortestPath}
              />
              <GraphLegend isGedcom={isGedcom} isAdvancedMode={isAdvancedMode} />

              {shortestPath && (
                <div className="absolute bottom-4 left-4 right-4 bg-gray-900 bg-opacity-90 border border-cyan-500/50 p-2 rounded text-xs text-cyan-200 backdrop-blur-sm animate-pulse">
                    Path Highlighted: {shortestPath.length} nodes involved.
                </div>
              )}
            </>
          ) : (
            <div className="flex flex-col items-center justify-center h-full text-center p-8">
              <UploadIcon className="w-24 h-24 text-gray-600 mb-6" />
              <h2 className="text-2xl font-semibold text-gray-300">Welcome to the Graph Analyzer</h2>
              <p className="mt-2 text-gray-400 max-w-md">
                Upload a file to start visualizing your network.
              </p>
            </div>
          )}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useRef, useState, useMemo } from 'react';
import { AnalysisResult, NodeObject, CentralityResult, DegreeDistributionResult, GraphData, NodeAnalysisResult } from '../types';
import Button from './ui/Button';
import Card from './ui/Card';
import Spinner from './ui/Spinner';
import SampleDataSelector from './SampleDataSelector';
import Tooltip from './ui/Tooltip';
import { InfoIcon, UploadIcon, BarChart2Icon, XCircleIcon, ChevronRightIcon, UsersIcon, SearchIcon, SparklesIcon, DownloadIcon } from './ui/Icons';
import * as exportService from '../services/graphExportService';

interface ControlPanelProps {
  onFileSelect: (file: File) => void;
  onAnalyze: () => void;
  onDetectCommunities: () => void;
  onSampleSelect: (content: string, type: 'ged' | 'txt', name: string) => void;
  analysisResult: AnalysisResult | null;
  isAnalyzing: boolean;
  isDetectingCommunities: boolean;
  error: string | null;
  hasGraphData: boolean;
  graphData: GraphData | null;
  selectedNode: NodeObject | null;
  selectedNodeStats: NodeAnalysisResult | null;
  onNodeSelect: (node: NodeObject, event?: any) => void;
  onClearSelection: () => void;
  isAdvancedMode: boolean;
  onToggleAdvancedMode: () => void;
  isGedcom: boolean;
  onGenerateAiInsights: () => void;
  aiSummary: string | null;
  isGeneratingAi: boolean;
}

const StatItem: React.FC<{ label: string; value: React.ReactNode; tooltip?: string; highlight?: boolean }> = ({ label, value, tooltip, highlight }) => (
    <div className={`flex justify-between items-center py-2 border-b border-gray-700/50 last:border-b-0 ${highlight ? 'bg-cyan-500/5 px-2 -mx-2 rounded' : ''}`}>
        <span className="text-xs text-gray-400 flex items-center gap-1">
            {label}
            {tooltip && (
                <Tooltip content={tooltip}>
                    <InfoIcon className="w-3.5 h-3.5 text-gray-600 cursor-help" />
                </Tooltip>
            )}
        </span>
        <span className={`text-sm font-bold ${highlight ? 'text-cyan-400' : 'text-white'}`}>{String(value)}</span>
    </div>
);

const RankingList: React.FC<{ label: string; items: CentralityResult[]; onNodeSelect: (n: NodeObject) => void }> = ({ label, items, onNodeSelect }) => {
    if (!items || items.length === 0 || !items.some(i => i.value > 0)) return null;
    return (
        <div className="mt-4 first:mt-0">
            <h4 className="text-[10px] font-bold text-cyan-500 uppercase tracking-widest mb-2">{label}</h4>
            <div className="space-y-1">
                {items.slice(0, 5).map((item, index) => (
                    <button 
                        key={item.node.id} 
                        onClick={() => onNodeSelect(item.node)}
                        className="w-full text-left text-xs text-gray-300 bg-gray-800/40 hover:bg-gray-700/60 px-2 py-1.5 rounded flex justify-between items-center transition-colors border border-transparent hover:border-cyan-500/30"
                    >
                       <span className="truncate pr-2">{index + 1}. {item.node.name || item.node.id}</span>
                       <span className="font-mono text-cyan-400 text-[10px]">{item.value.toFixed(2)}</span>
                    </button>
                ))}
            </div>
        </div>
    );
};

const ControlPanel: React.FC<ControlPanelProps> = ({
  onFileSelect,
  onAnalyze,
  onDetectCommunities,
  onSampleSelect,
  analysisResult,
  isAnalyzing,
  isDetectingCommunities,
  error,
  hasGraphData,
  graphData,
  selectedNode,
  selectedNodeStats,
  onNodeSelect,
  onClearSelection,
  isAdvancedMode,
  onToggleAdvancedMode,
  isGedcom,
  onGenerateAiInsights,
  aiSummary,
  isGeneratingAi
}) => {
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [searchQuery, setSearchQuery] = useState('');

  const filteredNodes = useMemo(() => {
    if (!searchQuery.trim() || !graphData) return [];
    const query = searchQuery.toLowerCase();
    return graphData.nodes.filter(node => 
        (node.name && node.name.toLowerCase().includes(query)) || 
        node.id.toLowerCase().includes(query)
    ).slice(0, 10);
  }, [searchQuery, graphData]);

  const neighbors = useMemo(() => {
    if (!selectedNode || !graphData) return [];
    const set = new Set<string>();
    graphData.links.forEach(link => {
        const sId = typeof link.source === 'object' ? (link.source as NodeObject).id : link.source;
        const tId = typeof link.target === 'object' ? (link.target as NodeObject).id : link.target;
        if(sId === selectedNode.id) set.add(tId);
        if(tId === selectedNode.id) set.add(sId);
    });
    const nodeMap = new Map(graphData.nodes.map(n => [n.id, n]));
    return Array.from(set).map(id => nodeMap.get(id)).filter(Boolean) as NodeObject[];
  }, [selectedNode, graphData]);

  const isLoading = isAnalyzing || isDetectingCommunities;

  // Identify if we have tree-specific metrics to show
  const hasTreeMetrics = analysisResult && (analysisResult.averageGenerationWidth !== 'N/A' || analysisResult.structureRatio !== 'N/A');

  return (
    <Card className="flex flex-col h-full max-h-full overflow-hidden shadow-2xl bg-gray-900 border-gray-800">
      <div className="flex-grow overflow-y-auto p-5 space-y-6 scrollbar-thin scrollbar-thumb-gray-800">

          {hasGraphData && (
              <div>
                <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Quick Search</h2>
                <div className="relative">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <SearchIcon className="h-4 w-4 text-gray-600" />
                    </div>
                    <input
                        type="text"
                        className="block w-full pl-9 pr-3 py-2 border border-gray-800 rounded-md leading-5 bg-gray-950 text-gray-300 placeholder-gray-700 focus:outline-none focus:ring-1 focus:ring-cyan-900 focus:border-cyan-800 sm:text-sm"
                        placeholder="Search node..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                {searchQuery && (
                    <div className="mt-1 bg-gray-900 border border-gray-800 rounded-md shadow-2xl max-h-40 overflow-y-auto z-50 relative">
                        {filteredNodes.length > 0 ? (
                            <ul className="py-1">
                                {filteredNodes.map(node => (
                                    <li key={node.id}>
                                        <button
                                            className="w-full text-left px-4 py-2 text-xs text-gray-400 hover:bg-gray-800 hover:text-cyan-400 truncate"
                                            onClick={() => { onNodeSelect(node); setSearchQuery(''); }}
                                        >
                                            {node.name || node.id}
                                        </button>
                                    </li>
                                ))}
                            </ul>
                        ) : (
                            <div className="px-4 py-2 text-[10px] text-gray-600 italic">No results</div>
                        )}
                    </div>
                )}
              </div>
          )}

          <div>
            <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Controls</h2>
            <div className="flex flex-col gap-2">
                <input type="file" ref={fileInputRef} onChange={(e) => e.target.files?.[0] && onFileSelect(e.target.files[0])} className="hidden" accept=".ged,.txt" />
                <Button onClick={() => fileInputRef.current?.click()} icon={<UploadIcon className="w-4 h-4" />}>Upload File</Button>

                {isGedcom && (
                    <div className="flex items-center justify-between bg-gray-950 p-2 rounded border border-gray-800">
                        <span className="text-[10px] font-bold text-gray-500 uppercase tracking-tight">Advanced Entities</span>
                        <button onClick={onToggleAdvancedMode} className={`relative inline-flex h-4 w-8 items-center rounded-full transition-colors ${isAdvancedMode ? 'bg-cyan-600' : 'bg-gray-800'}`}>
                            <span className={`${isAdvancedMode ? 'translate-x-4' : 'translate-x-1'} inline-block h-2 w-2 transform rounded-full bg-white transition-transform`} />
                        </button>
                    </div>
                )}

                <div className="grid grid-cols-2 gap-2">
                    <Button onClick={onAnalyze} disabled={!hasGraphData || isLoading} variant="secondary" icon={isAnalyzing ? <Spinner /> : <BarChart2Icon className="w-4 h-4" />}>
                        {isAnalyzing ? '...' : 'Analyze'}
                    </Button>
                    <Button onClick={onDetectCommunities} disabled={!analysisResult || isLoading} variant="secondary" icon={isDetectingCommunities ? <Spinner /> : <UsersIcon className="w-4 h-4" />}>
                        {isDetectingCommunities ? '...' : 'Groups'}
                    </Button>
                </div>
            </div>
        </div>

        {analysisResult?.isLargeGraph && (
            <div className="bg-amber-950/20 border border-amber-900/50 p-3 rounded-md">
                <div className="flex items-center gap-2 text-amber-500 mb-1">
                    <InfoIcon className="w-4 h-4" />
                    <span className="text-[10px] font-bold uppercase">מצב ביצועים פעיל</span>
                </div>
                <p className="text-[10px] text-amber-200/70 leading-relaxed">
                    מכיוון שהעץ מכיל מעל 3,000 צמתים, חלק מהמדדים הכבדים (מרכזיות ביניים, קוטר העץ) הושבתו כדי למנוע קריסה.
                </p>
            </div>
        )}

        {hasGraphData && graphData && (
            <div>
                <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Export Network</h2>
                <div className="flex flex-col gap-2">
                    <Button 
                        onClick={() => exportService.exportToJson(graphData)} 
                        variant="secondary" 
                        icon={<DownloadIcon className="w-4 h-4" />}
                    >
                        Export JSON
                    </Button>
                    <div className="grid grid-cols-2 gap-2">
                        <Button 
                            onClick={() => exportService.exportToEdgeListCsv(graphData)} 
                            variant="secondary" 
                            className="text-[10px]"
                        >
                            CSV Edges
                        </Button>
                        <Button 
                            onClick={() => exportService.exportToNodeListCsv(graphData)} 
                            variant="secondary"
                            className="text-[10px]"
                        >
                            CSV Nodes
                        </Button>
                    </div>
                </div>
            </div>
        )}

        {!hasGraphData && (
            <div>
                <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Samples</h2>
                <SampleDataSelector onSelect={onSampleSelect} />
            </div>
        )}

        {selectedNode && (
          <div className="mt-4 pt-4 border-t border-gray-800">
              <div className="flex justify-between items-center mb-2">
                  <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Selection</h2>
                  <button onClick={onClearSelection} className="text-gray-600 hover:text-white"><XCircleIcon className="w-4 h-4" /></button>
              </div>
              <div className="bg-gray-950 p-3 rounded border border-gray-800">
                  <h3 className="font-bold text-cyan-400 truncate text-sm mb-2">{selectedNode.name || selectedNode.id}</h3>
                  <div className="space-y-0.5">
                     <StatItem label="Neighbors" value={neighbors.length} />
                     {selectedNodeStats && (
                        <>
                          <StatItem label="Total Reachable" value={selectedNodeStats.reachableNodes} />
                          <StatItem label="Clustering" value={selectedNodeStats.clusteringCoefficient.toFixed(3)} />
                          <StatItem label="Eccentricity" value={selectedNodeStats.eccentricity} />
                        </>
                     )}
                  </div>
              </div>
          </div>
        )}

        {analysisResult && (
          <div className="mt-4 pt-4 border-t border-gray-800">
              <div className="flex justify-between items-center mb-4">
                  <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Network Statistics</h2>
                  <button onClick={onGenerateAiInsights} disabled={isGeneratingAi} className="text-cyan-400 hover:text-cyan-300 disabled:text-gray-700 flex items-center gap-1 text-[10px] font-bold">
                      {isGeneratingAi ? <Spinner /> : <SparklesIcon className="w-3 h-3" />} AI SUMMARY
                  </button>
              </div>

              {aiSummary && (
                  <div className="mb-4 bg-gray-950 border-l-2 border-cyan-500 p-3 text-xs text-gray-300 italic leading-relaxed">
                      {aiSummary}
                  </div>
              )}

              <div className="space-y-4">
                {/* Tree-Specific Highlights */}
                {hasTreeMetrics && (
                    <div className="bg-cyan-950/20 rounded-md p-3 border border-cyan-900/50 space-y-1">
                        <h4 className="text-[10px] font-bold text-cyan-600 uppercase tracking-widest mb-2 border-b border-cyan-900/30 pb-1">מבנה עץ יוחסין</h4>
                        <StatItem 
                            label="היחס בין עץ רחב לעמוק" 
                            value={analysisResult.structureRatio} 
                            highlight={true} 
                            tooltip="היחס בין עומק הענפים הממוצע לרוחב הדורות הממוצע. מספר גבוה מעיד על שושלת עמוקה, מספר נמוך מעיד על עץ רחב מאוד."
                        />
                        <StatItem label="רוחב דור ממוצע" value={analysisResult.averageGenerationWidth} />
                        <StatItem label="עומק ענפים ממוצע" value={analysisResult.averageLeafDepth} />

                        <div className="pt-2 mt-2 border-t border-cyan-900/30">
                            <StatItem 
                                label="קריסת אילן ממוצעת" 
                                value={analysisResult.averagePedigreeCollapse} 
                                tooltip="מדד ה-PCI הממוצע באוכלוסייה. (אבות תיאורטיים - אבות בפועל) / אבות תיאורטיים."
                            />
                            <StatItem 
                                label="סך אנשים עם שושלת קורסת" 
                                value={analysisResult.totalPedigreeCollapseOccurrences} 
                                tooltip="מספר הפרטים בעץ שיש להם לפחות אב קדמון אחד המופיע ביותר מנתיב אחד (כלומר, הוריהם חולקים קשר דם)."
                            />
                        </div>
                    </div>
                )}

                {/* Core Table */}
                <div className="bg-gray-950/50 rounded-md p-2 border border-gray-800/50">
                    <StatItem label="Node Count" value={analysisResult.nodeCount} />
                    <StatItem label="Edge Count" value={analysisResult.edgeCount} />
                    <StatItem label="Graph Density" value={analysisResult.graphDensity} />
                    <StatItem label="Diameter" value={analysisResult.diameter} />
                    <StatItem label="Avg Path Length" value={analysisResult.averageShortestPath} />
                    <StatItem label="Connected Components" value={analysisResult.componentCount} />
                    <StatItem label="Largest Sub-graph" value={analysisResult.largestComponentSize} />
                </div>

                {/* Degree Distribution */}
                {analysisResult.degreeDistribution && !analysisResult.isLargeGraph && (
                    <div className="mt-4">
                        <h4 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-2">Degree Distribution</h4>
                        <div className="max-h-32 overflow-y-auto space-y-1 bg-gray-950/30 p-2 rounded">
                            {analysisResult.degreeDistribution.map(d => (
                                <div key={d.degree} className="flex justify-between text-[10px] text-gray-400">
                                    <span>Degree {d.degree}:</span>
                                    <span className="font-bold text-gray-200">{d.count} nodes</span>
                                </div>
                            ))}
                        </div>
                    </div>
                )}

                {/* Rank lists */}
                <div className="space-y-6">
                    <RankingList label="Degree Centrality (Top Hubs)" items={analysisResult.centralityByConnections || []} onNodeSelect={onNodeSelect} />
                    {!analysisResult.isLargeGraph && (
                        <RankingList label="Betweenness Centrality (Bridges)" items={analysisResult.betweennessCentrality || []} onNodeSelect={onNodeSelect} />
                    )}
                    {isGedcom && (
                        <>
                            <RankingList label="Influence by Descendants" items={analysisResult.centralityByDescendants || []} onNodeSelect={onNodeSelect} />
                            <RankingList label="Influence by Ancestors" items={analysisResult.centralityByAncestors || []} onNodeSelect={onNodeSelect} />
                        </>
                    )}
                </div>

                {/* Communities */}
                {analysisResult.communities && !analysisResult.isLargeGraph && (
                    <div className="mt-4">
                        <h4 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-2">Communities Detected</h4>
                        <div className="space-y-1.5">
                            {analysisResult.communities.slice(0, 5).map((comm, idx) => (
                                <details key={idx} className="bg-gray-950 border border-gray-800 rounded group">
                                    <summary className="text-[10px] text-gray-400 p-2 cursor-pointer flex justify-between">
                                        <span>Group {idx + 1} ({comm.length} members)</span>
                                        <ChevronRightIcon className="w-3 h-3 group-open:rotate-90" />
                                    </summary>
                                    <div className="p-2 pt-0 grid grid-cols-2 gap-1 border-t border-gray-800/50">
                                        {comm.slice(0, 10).map(n => (
                                            <button key={n.id} onClick={() => onNodeSelect(n)} className="text-[9px] text-gray-500 hover:text-cyan-400 truncate text-left">
                                                {n.name || n.id}
                                            </button>
                                        ))}
                                        {comm.length > 10 && <span className="text-[8px] text-gray-700">+{comm.length - 10} more...</span>}
                                    </div>
                                </details>
                            ))}
                        </div>
                    </div>
                )}
              </div>
          </div>
        )}
      </div>
    </Card>
  );
};

