                <Button onClick={onAnalyze} disabled={!hasGraphData || isAnalyzing} variant="secondary" icon={isAnalyzing ? <Spinner /> : <BarChart2Icon className="w-4 h-4" />}>
                    {isAnalyzing ? 'Analyzing...' : 'Analyze Network'}
