                  )}
              </div>
          </div>
        )}

        {analysisResult && (
          <div className="mt-4 pt-4 border-t border-gray-800 space-y-6">
              <div>
                  <h2 className="text-[10px] font-bold text-gray-500 uppercase tracking-widest mb-3">Network Summary</h2>
