                      <StatItem label="Density" value={analysisResult.graphDensity} />
                      <StatItem label="Components" value={analysisResult.componentCount} />
                      <StatItem label="Max Sub-graph" value={analysisResult.largestComponentSize} />
                  </div>
              </div>

              {isGedcom && (
                  <div className="bg-cyan-950/20 rounded-md p-3 border border-cyan-900/50 space-y-1">
                      <h4 className="text-[10px] font-bold text-cyan-600 uppercase tracking-widest mb-2 border-b border-cyan-900/30 pb-1">Genetics & Lineage</h4>
                      <StatItem label="שושלת קורסת (PCI)" value={analysisResult.averagePedigreeCollapse || 'N/A'} tooltip="מדד ה-PCI הממוצע. 0=אין כפילויות, 1=כפילות מלאה." />
