/**
 * Formats numeric values. 
 * Small numbers (abs < 0.001) are shown in scientific notation (e.g., 3.22E-6).
 * Larger numbers are shown as standard decimals with up to 10 places, trimmed.
 */
const formatStatValue = (val: any): string => {
    if (val === null || val === undefined) return 'N/A';
    if (val === 'N/A' || (typeof val === 'string' && val.includes('Skipped'))) return val;

    let num = typeof val === 'number' ? val : parseFloat(String(val));
    if (isNaN(num)) return String(val);
    if (num === 0) return '0';

    const absNum = Math.abs(num);

    // Threshold for scientific notation (3.2E-6 style)
    if (absNum > 0 && absNum < 0.001) {
        return num.toExponential(2).toUpperCase().replace('+', '');
    }

    // Standard decimal formatting for values >= 0.001
    // toFixed(10) ensures we don't get scientific notation from the engine, 
    // then we trim trailing zeros and potential trailing dot.
    const formatted = num.toFixed(10).replace(/\.?0+$/, '');
    return formatted === '-0' ? '0' : formatted;
};

