import React, { Component, ErrorInfo, ReactNode } from 'react';
import { AlertTriangleIcon } from './ui/Icons';

interface Props {
  children?: ReactNode;
}

interface State {
  hasError: boolean;
}

/**
 * ErrorBoundary catches errors in its child component tree and displays a fallback UI.
 */
// Use the directly imported Component class to ensure state and props are correctly inherited and recognized by TypeScript.
class ErrorBoundary extends Component<Props, State> {
  // Initialize state using a class property for more reliable TypeScript type inference compared to constructor-based assignment.
  state: State = {
    hasError: false
  };

  // Static method for updating error state based on an exception.
  static getDerivedStateFromError(_: Error): State {
    // Update state so the next render will show the fallback UI.
    return { hasError: true };
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    // Log the error to console or an error monitoring service.
    console.error('Uncaught error:', error, errorInfo);
  }

  render() {
    // Inheriting from Component provides access to the 'state' and 'props' properties.
    if (this.state.hasError) {
      return (
        <div className="flex items-center justify-center h-screen bg-gray-900 text-gray-300">
            <div className="text-center p-8 bg-gray-800 rounded-lg shadow-2xl border border-red-700 max-w-md">
                <AlertTriangleIcon className="w-16 h-16 text-red-500 mx-auto mb-4" />
                <h1 className="text-2xl font-bold text-white mb-2">Something went wrong.</h1>
                <p className="text-gray-400">
                    An unexpected error has occurred. Please try refreshing the page.
                    If the problem persists, please check the console for more details.
                </p>
                <button
                    onClick={() => window.location.reload()}
                    className="mt-6 px-4 py-2 bg-cyan-600 text-white font-semibold rounded-md hover:bg-cyan-700 transition-colors"
                >
                    Refresh Page
                </button>
            </div>
        </div>
      );
    }

    // Accessing this.props.children which is provided by the Component base class.
    return this.props.children;
  }
}

export default ErrorBoundary;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { GraphData, AnalysisResult, NodeObject, NodeAnalysisResult } from './types';
import { parseEdgeList, parseGedcom } from './services/graphService';
import ControlPanel from './components/ControlPanel';
import GraphVisualizer from './components/GraphVisualizer';
import GraphLegend from './components/GraphLegend';
import { UploadIcon, GraphIcon } from './components/ui/Icons';
import { GoogleGenAI } from "@google/genai";

const GRAPH_WORKER_CODE = `
const bfs = (startNodeId, adjacencyList) => {
  const distances = new Map([[startNodeId, 0]]);
  const queue = [startNodeId];
  let maxDistance = 0;
  let totalDistance = 0;

  let head = 0;
  while(head < queue.length) {
    const currentNodeId = queue[head++];
    const currentDistance = distances.get(currentNodeId);

    if (currentDistance > maxDistance) maxDistance = currentDistance;
    totalDistance += currentDistance;

    const neighbors = adjacencyList.get(currentNodeId) || [];
    for (let i = 0; i < neighbors.length; i++) {
      const neighborId = neighbors[i];
      if (!distances.has(neighborId)) {
        distances.set(neighborId, currentDistance + 1);
        queue.push(neighborId);
      }
    }
  }
  return { distances, maxDistance, totalDistance, reachableCount: distances.size };
};

const findConnectedComponents = (graphData, adjacencyList) => {
    const components = [];
    const visited = new Set();
    for(const node of graphData.nodes) {
        if(!visited.has(node.id)) {
            const component = [];
            const queue = [node.id];
            visited.add(node.id);
            let head = 0;
            while(head < queue.length) {
                const u = queue[head++];
                component.push(u);
                for(const v of adjacencyList.get(u) || []) {
                    if(!visited.has(v)) {
                        visited.add(v);
                        queue.push(v);
                    }
                }
            }
            components.push(component);
        }
    }
    return components;
};

// --- Genealogical Helpers (Iterative to prevent stack overflow) ---
const createMemoizedCounter = (map) => {
    const memo = new Map();
    const count = (startNodeId) => {
        if (memo.has(startNodeId)) return memo.get(startNodeId);

        const allRelated = new Set();
        const stack = [startNodeId];
        const visited = new Set([startNodeId]);

        while (stack.length > 0) {
            const current = stack.pop();
            const neighbors = map.get(current) || [];
            for (const neighbor of neighbors) {
                if (!visited.has(neighbor)) {
                    visited.add(neighbor);
                    allRelated.add(neighbor);

                    // Optimization: if we already calculated this sub-tree, merge it
                    if (memo.has(neighbor)) {
                        const sub = memo.get(neighbor);
                        for (const subId of sub) {
                            allRelated.add(subId);
                            visited.add(subId);
                        }
                    } else {
                        stack.push(neighbor);
                    }
                }
            }
        }
        memo.set(startNodeId, allRelated);
        return allRelated;
    };
    return count;
};

const calculatePedigreeCollapse = (graphData) => {
    const nodes = graphData.nodes;
    if (nodes.length > 3000) return { avg: 'N/A (Too Large)', count: 0 };

    const parentMap = new Map();
    graphData.links.forEach(l => {
        if (l.type === 'parent-child') {
            const s = typeof l.source === 'object' ? l.source.id : l.source;
            const t = typeof l.target === 'object' ? l.target.id : l.target;
            if (!parentMap.has(t)) parentMap.set(t, []);
            parentMap.get(t).push(s);
        }
    });

    const getAncestors = createMemoizedCounter(parentMap);
    let occurrences = 0;
    let peopleWithAncestors = 0;

    nodes.forEach(node => {
        const actualSet = getAncestors(node.id);
        if (actualSet.size > 0) {
            peopleWithAncestors++;
            // Basic indicator: more than 2 parents or unusual lineage overlap
            if ((parentMap.get(node.id)?.length || 0) > 2) occurrences++; 
        }
    });

    return { 
        avg: peopleWithAncestors > 0 ? (occurrences / peopleWithAncestors).toFixed(4) : "0", 
        count: occurrences 
    };
};

const analyzeGraph = (graphData, adjacencyList) => {
    const nodeCount = graphData.nodes.length;
    const edgeCount = graphData.links.length;
    const isLarge = nodeCount >= 5000;
    const isGedcom = graphData.links.some(l => l.type === 'parent-child' || l.type === 'marriage');

    const components = findConnectedComponents(graphData, adjacencyList);
    const largestComponent = components.reduce((l, c) => c.length > l.length ? c : l, []);

    let diameter = 0;
    let avgPath = 0;
    if (largestComponent.length > 1) {
        const sampleSize = isLarge ? 100 : Math.min(largestComponent.length, 500);
        const pivots = largestComponent.slice().sort(() => 0.5 - Math.random()).slice(0, sampleSize);
        let totalPathSum = 0;
        let totalPairs = 0;
        let maxFoundDist = 0;

        for (const startId of pivots) {
            const { maxDistance, totalDistance, reachableCount } = bfs(startId, adjacencyList);
            maxFoundDist = Math.max(maxFoundDist, maxDistance);
            totalPathSum += totalDistance;
            totalPairs += (reachableCount - 1);
        }
        diameter = maxFoundDist;
        avgPath = totalPairs > 0 ? (totalPathSum / totalPairs) : 0;
    }

    const result = {
        nodeCount,
        edgeCount,
        componentCount: components.length,
        isConnected: components.length === 1,
        graphDensity: ( (2 * edgeCount) / (nodeCount * (nodeCount - 1)) || 0 ).toFixed(10),
        largestComponentSize: largestComponent.length,
        isLargeGraph: isLarge,
        diameter: isLarge ? diameter + " (משוער)" : diameter,
        averageShortestPath: isLarge ? avgPath.toFixed(2) + " (משוער)" : avgPath.toFixed(2),
        centralityByConnections: graphData.nodes.map(n => ({
            node: n, value: (adjacencyList.get(n.id) || []).length
        })).sort((a,b) => b.value - a.value).slice(0, 5)
    };

    if (isGedcom) {
        const childMap = new Map();
        const parentMap = new Map();
        graphData.links.forEach(l => {
            if (l.type === 'parent-child') {
                const s = typeof l.source === 'object' ? l.source.id : l.source;
                const t = typeof l.target === 'object' ? l.target.id : l.target;
                if (!childMap.has(s)) childMap.set(s, []);
                childMap.get(s).push(t);
                if (!parentMap.has(t)) parentMap.set(t, []);
                parentMap.get(t).push(s);
            }
        });

        const countDescendants = createMemoizedCounter(childMap);
        const countAncestors = createMemoizedCounter(parentMap);

        result.centralityByDescendants = graphData.nodes
            .map(n => ({ node: n, value: countDescendants(n.id).size }))
            .sort((a,b) => b.value - a.value).slice(0, 5);

        result.centralityByAncestors = graphData.nodes
            .map(n => ({ node: n, value: countAncestors(n.id).size }))
            .sort((a,b) => b.value - a.value).slice(0, 5);

        const pci = calculatePedigreeCollapse(graphData);
        result.averagePedigreeCollapse = pci.avg;
        result.totalPedigreeCollapseOccurrences = pci.count;

        if (largestComponent.length > 0) {
            const roots = largestComponent.filter(id => !parentMap.has(id));
            const genCounts = new Map();
            const leafDepths = [];

            const queue = (roots.length ? roots : [largestComponent[0]]).map(id => ({id, d: 0}));
            const visited = new Set(roots.length ? roots : [largestComponent[0]]);
            let head = 0;
            while(head < queue.length) {
                const {id, d} = queue[head++];
                genCounts.set(d, (genCounts.get(d) || 0) + 1);
                const children = childMap.get(id) || [];
                if (children.length === 0) leafDepths.push(d);
                for(const c of children) {
                    if(!visited.has(c)) { visited.add(c); queue.push({id: c, d: d+1}); }
                }
            }
            const totalNodes = Array.from(genCounts.values()).reduce((a,b)=>a+b, 0);
            result.averageGenerationWidth = (totalNodes / genCounts.size).toFixed(2);
            result.averageLeafDepth = (leafDepths.reduce((a,b)=>a+b, 0) / (leafDepths.length || 1)).toFixed(2);
        }
    }
    return result;
};

self.onmessage = (event) => {
  try {
    const { type, graphData, nodeId } = event.data;
    const adjacencyList = new Map();
    graphData.nodes.forEach(n => adjacencyList.set(n.id, []));
    graphData.links.forEach(l => {
        const s = typeof l.source === 'object' ? l.source.id : l.source;
        const t = typeof l.target === 'object' ? l.target.id : l.target;
        if (adjacencyList.has(s) && adjacencyList.has(t)) {
            adjacencyList.get(s).push(t);
            adjacencyList.get(t).push(s);
        }
    });

    if (type === 'analyze') {
        const result = analyzeGraph(graphData, adjacencyList);
        self.postMessage({ type: 'analysis_success', result });
    } else if (type === 'analyzeNode' && nodeId) {
        const { maxDistance, distances } = bfs(nodeId, adjacencyList);
        self.postMessage({ 
            type: 'node_analysis_success', 
            result: { 
                id: nodeId, degree: (adjacencyList.get(nodeId) || []).length,
                eccentricity: maxDistance, reachableNodes: distances.size
            } 
        });
    }
  } catch (error) {
    self.postMessage({ type: 'error', error: error.message });
  }
};
`;

const App: React.FC = () => {
  const [graphData, setGraphData] = useState<GraphData | null>(null);
  const [analysisResult, setAnalysisResult] = useState<AnalysisResult | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [isGedcom, setIsGedcom] = useState<boolean>(false);
  const [statusMessage, setStatusMessage] = useState<string>('');
  const [selectedNode, setSelectedNode] = useState<NodeObject | null>(null);
  const [selectedNodeStats, setSelectedNodeStats] = useState<NodeAnalysisResult | null>(null);
  const [hoveredNode, setHoveredNode] = useState<NodeObject | null>(null);
  const fgRef = useRef<any>(null);
  const workerRef = useRef<Worker | null>(null);
  const [rawFileContent, setRawFileContent] = useState<string | null>(null);
  const [isAdvancedMode, setIsAdvancedMode] = useState<boolean>(false);
  const [aiSummary, setAiSummary] = useState<string | null>(null);
  const [isGeneratingAi, setIsGeneratingAi] = useState<boolean>(false);

  useEffect(() => {
    const blob = new Blob([GRAPH_WORKER_CODE], { type: 'application/javascript' });
    const objectUrl = URL.createObjectURL(blob);
    const worker = new Worker(objectUrl);
    workerRef.current = worker;
    worker.addEventListener('message', (event) => {
      const { type, result, error: workerError } = event.data;
      if (type === 'analysis_success') {
        setIsAnalyzing(false);
        setAnalysisResult(result);
        setStatusMessage('Analysis complete.');
      } else if (type === 'node_analysis_success') {
        setSelectedNodeStats(result);
      } else if (type === 'error') {
        setIsAnalyzing(false);
        setError(workerError);
      }
    });
    return () => { worker.terminate(); URL.revokeObjectURL(objectUrl); };
  }, []);

  const handleFileSelect = useCallback((file: File) => {
    setError(null); setAnalysisResult(null); setSelectedNode(null); setGraphData(null); setAiSummary(null);
    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const content = e.target?.result as string;
        setRawFileContent(content);
        const isGedcomFile = file.name.toLowerCase().endsWith('.ged');
        setIsGedcom(isGedcomFile);
        const data = isGedcomFile ? parseGedcom(content, false) : parseEdgeList(content);
        setGraphData(data);
        setStatusMessage(`Loaded ${file.name}.`);
      } catch (err) { setError('Error parsing file.'); }
    };
    reader.readAsText(file);
  }, []);

  const handleSampleSelect = useCallback((content: string, type: 'ged' | 'txt', name: string) => {
    setError(null); setAnalysisResult(null); setSelectedNode(null); setAiSummary(null);
    setRawFileContent(content);
    const isGedcomFile = type === 'ged';
    setIsGedcom(isGedcomFile);
    const data = isGedcomFile ? parseGedcom(content, false) : parseEdgeList(content);
    setGraphData(data);
    setStatusMessage(`Loaded sample: ${name}.`);
  }, []);

  const handleAnalyze = useCallback(() => {
    if (!graphData || !workerRef.current) return;
    setAnalysisResult(null); setIsAnalyzing(true);
    workerRef.current.postMessage({ type: 'analyze', graphData });
  }, [graphData]);

  const handleNodeClick = useCallback((node: NodeObject) => {
    setSelectedNode(node); setSelectedNodeStats(null);
    if (graphData && workerRef.current) {
        workerRef.current.postMessage({ type: 'analyzeNode', graphData, nodeId: node.id });
    }
  }, [graphData]);

  const handleToggleAdvancedMode = useCallback(() => {
    if (!rawFileContent || !isGedcom) return;
    const newMode = !isAdvancedMode;
    setIsAdvancedMode(newMode);
    setAnalysisResult(null); setAiSummary(null);
    try { const data = parseGedcom(rawFileContent, newMode); setGraphData(data); } catch (err) { setError('Parse error.'); }
  }, [rawFileContent, isGedcom, isAdvancedMode]);

  const handleGenerateAiInsights = useCallback(async () => {
    if (!analysisResult) return;
    setIsGeneratingAi(true); setAiSummary(null);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const prompt = `אתה מומחה גנאלוגיה ורשתות. נתח את הנתונים הבאים על עץ משפחה/רשת חברתית והסבר מה ניתן ללמוד מהם על המבנה המשפחתי, צמתים מרכזיים ודפוסים חריגים: ${JSON.stringify(analysisResult)}. ענה בעברית.`;
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: { thinkingConfig: { thinkingBudget: 4096 } }
      });
      setAiSummary(response.text || 'לא נוצרו תובנות.');
    } catch (err) { setError('הפקת תובנות AI נכשלה.'); } finally { setIsGeneratingAi(false); }
  }, [analysisResult]);

  return (
    <div className="h-screen flex flex-col font-sans bg-gray-900 text-gray-200 overflow-hidden">
      <header className="bg-gray-800 bg-opacity-50 backdrop-blur-sm shadow-lg p-4 z-10 border-b border-gray-700 flex-shrink-0">
        <div className="container mx-auto flex items-center gap-4">
          <GraphIcon className="w-8 h-8 text-cyan-400" />
          <h1 className="text-2xl font-bold tracking-tight text-white">מנתח רשתות גנאלוגי</h1>
          {statusMessage && <span className="ml-auto text-xs text-cyan-500 animate-pulse">{statusMessage}</span>}
        </div>
      </header>
      <main className="flex-grow flex flex-col md:flex-row container mx-auto p-4 gap-4 min-h-0">
        <div className="w-full md:w-1/3 lg:w-1/4 flex-shrink-0 h-full overflow-hidden flex flex-col">
          <ControlPanel
            onFileSelect={handleFileSelect}
            onAnalyze={handleAnalyze}
            onDetectCommunities={() => {}}
            onSampleSelect={handleSampleSelect}
            analysisResult={analysisResult}
            isAnalyzing={isAnalyzing}
            isDetectingCommunities={false}
            error={error}
            hasGraphData={!!graphData}
            graphData={graphData}
            selectedNode={selectedNode}
            selectedNodeStats={selectedNodeStats}
            onNodeSelect={handleNodeClick}
            onClearSelection={() => setSelectedNode(null)}
            isAdvancedMode={isAdvancedMode}
            onToggleAdvancedMode={handleToggleAdvancedMode}
            isGedcom={isGedcom}
            onGenerateAiInsights={handleGenerateAiInsights}
            aiSummary={aiSummary}
            isGeneratingAi={isGeneratingAi}
          />
        </div>
        <div className="flex-grow bg-gray-800 rounded-lg shadow-2xl overflow-hidden relative border border-gray-700 h-full">
          {graphData ? (
            <>
              <GraphVisualizer
                fgRef={fgRef}
                graphData={graphData}
                onNodeClick={handleNodeClick}
                onBackgroundClick={() => setSelectedNode(null)}
                hoveredNode={hoveredNode}
                onNodeHover={setHoveredNode}
                selectedNode={selectedNode}
                analysisResult={analysisResult}
              />
              <GraphLegend isGedcom={isGedcom} isAdvancedMode={isAdvancedMode} />
            </>
          ) : (
