                  <RankingList title="דירוג מתווכים (מרכזיות ביניים)" items={analysisResult.betweennessCentrality} onNodeClick={onNodeSelect} />
                  <RankingList title="מרכזיות (מספר קשרים)" items={analysisResult.centralityByConnections} onNodeClick={onNodeSelect} />

                  {isGedcom && (
                      <>
                        <div className="bg-cyan-950/20 rounded-md p-3 border border-cyan-900/50">
                            <h4 className="text-[10px] font-bold text-cyan-600 uppercase tracking-widest mb-2 border-b border-cyan-900/30 pb-1">מבנה גנאלוגי</h4>
                            <StatItem label="רוחב דור ממוצע" value={analysisResult.averageGenerationWidth} />
                            <StatItem label="עומק עלים ממוצע" value={analysisResult.averageLeafDepth} />
                            <StatItem label="קריסת שושלת (PCI)" value={analysisResult.averagePedigreeCollapse} tooltip="מדד לכמות האבות המשותפים. 0=עץ מושלם." />
                            <StatItem label="אנשים עם כפילות" value={analysisResult.totalPedigreeCollapseOccurrences} />
                        </div>

                        <div className="grid grid-cols-1 gap-1">
                            <RankingList title="הכי הרבה צאצאים" items={analysisResult.centralityByDescendants} onNodeClick={onNodeSelect} />
                            <RankingList title="הכי הרבה אבות קדמונים" items={analysisResult.centralityByAncestors} onNodeClick={onNodeSelect} />
                        </div>
                      </>
                  )}
              </div>

              <div className="pt-2">
                  <Button onClick={onGenerateAiInsights} disabled={isGeneratingAi} className="bg-gradient-to-r from-purple-600 to-cyan-600 hover:from-purple-500 hover:to-cyan-500" icon={isGeneratingAi ? <Spinner /> : <SparklesIcon className="w-4 h-4" />}>
                    {isGeneratingAi ? 'מייצר תובנות...' : 'תובנות Gemini AI'}
                  </Button>
                  {aiSummary && (
                      <div className="mt-4 p-4 bg-gray-950 border border-purple-900/30 rounded-lg text-xs text-gray-300 leading-relaxed shadow-inner animate-in zoom-in-95 duration-500">
                          <div className="flex items-center gap-2 mb-2 text-purple-400 font-bold uppercase tracking-widest text-[10px]">
                              <SparklesIcon className="w-3 h-3" />
                              ניתוח אינטליגנטי
                          </div>
                          <div className="whitespace-pre-wrap leading-normal">{aiSummary}</div>
                      </div>
                  )}
              </div>
          </div>
        )}
      </div>
    </Card>
  );
};

