const DegreeHistogram: React.FC<{ data: { degree: number; count: number }[], totalNodes: number }> = ({ data, totalNodes }) => {
    const [useLogScale, setUseLogScale] = useState(false);

    if (!data || data.length === 0) return null;

    const maxCount = Math.max(...data.map(d => d.count)) || 1;

    // Calculate Mode and Average for a small summary
    const mode = data.reduce((prev, current) => (prev.count > current.count) ? prev : current).degree;
    const avg = (data.reduce((acc, curr) => acc + (curr.degree * curr.count), 0) / totalNodes).toFixed(1);

    return (
        <div className="mt-6 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <div className="flex items-center justify-between mb-3 border-l-2 border-cyan-500 pl-2">
                <h2 className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">התפלגות קשרים</h2>
                <button 
                    onClick={() => setUseLogScale(!useLogScale)}
                    className={`text-[9px] px-2 py-0.5 rounded border transition-colors ${useLogScale ? 'bg-cyan-900/40 border-cyan-700 text-cyan-300' : 'bg-gray-800 border-gray-700 text-gray-500'}`}
                >
                    {useLogScale ? 'לוגריתמי' : 'ליניארי'}
                </button>
            </div>

            <div className="relative group bg-gray-950/40 p-3 rounded-lg border border-gray-800/50 shadow-inner overflow-hidden">
                {/* Background lines for scale feeling */}
                <div className="absolute inset-x-0 top-0 bottom-0 pointer-events-none flex flex-col justify-between opacity-5 px-3 py-2">
                    {[...Array(5)].map((_, i) => <div key={i} className="border-t border-white w-full" />)}
                </div>

                <div className="flex items-end gap-[3px] h-32 w-full overflow-x-auto pb-1 scrollbar-thin scrollbar-thumb-gray-800 scrollbar-track-transparent">
                    {data.map((d, i) => {
                        const rawRatio = d.count / maxCount;
                        const logRatio = Math.log10(d.count + 1) / Math.log10(maxCount + 1);
                        const heightPct = (useLogScale ? logRatio : rawRatio) * 100;
                        const percentage = ((d.count / totalNodes) * 100).toFixed(1);

                        return (
                            <div key={i} className="flex-1 flex flex-col justify-end h-full min-w-[10px] group/bar">
                                <Tooltip content={
                                    <div className="text-center">
                                        <div className="font-bold text-cyan-400">{d.degree} קשרים</div>
                                        <div className="text-[10px] text-gray-400">{d.count} צמתים ({percentage}%)</div>
                                    </div>
                                }>
                                    <div className="w-full h-full flex flex-col justify-end">
                                        <div 
                                            className="bg-gradient-to-t from-cyan-600 to-cyan-400 group-hover/bar:from-cyan-400 group-hover/bar:to-white transition-all rounded-t-[2px] w-full shadow-[0_0_10px_rgba(6,182,212,0.1)] group-hover/bar:shadow-[0_0_15px_rgba(6,182,212,0.4)]" 
                                            style={{ 
                                                height: `${Math.max(heightPct, 2)}%`,
                                                minHeight: '2px' 
                                            }} 
                                        />
                                    </div>
                                </Tooltip>
                            </div>
                        );
                    })}
                </div>
            </div>

            <div className="flex justify-between text-[9px] text-gray-600 mt-2 px-1 font-mono">
                <div className="flex gap-3">
                    <span>מינימום: <b className="text-gray-400">{data[0].degree}</b></span>
                    <span>מקסימום: <b className="text-gray-400">{data[data.length - 1].degree}</b></span>
                </div>
                <div className="flex gap-3">
                    <span>שכיח: <b className="text-cyan-600">{mode}</b></span>
                    <span>ממוצע: <b className="text-cyan-600">{avg}</b></span>
                </div>
            </div>
        </div>
    );
};

